/* =========================================================================
 *  TURN TEXT INTEGRITY  (Stabilization Stage 1, 2026-05-27)
 *
 *  Moved to utils/logging.js (Stage 3, 2026-05-27):
 *    - _turnTextIntegrityEnabled
 *    - _veraTurnSeq + _nextVeraTurnId
 *    - logTurnTextIntegrity (+ window alias)
 *
 *  `_readLatestUserBubbleText` (below) STAYS in app.js because four other
 *  Work-Mode bubble-preservation sites also call it; the moved logger
 *  reaches it via the shared classic-script global lexical environment.
 *
 *  Silence with:  localStorage.setItem("VERA_DEBUG_TURN_TEXT", "0")
 *  Re-enable with: localStorage.removeItem("VERA_DEBUG_TURN_TEXT")
 * ========================================================================= */

/** Read the latest USER bubble's plain text from the DOM, ignoring the
 *  translucent interrupt-detection preview. Returns `null` when no user
 *  bubble is currently mounted (typical for work-mode typed turns where the
 *  bubble only appears after the server NDJSON meta arrives). */
function _readLatestUserBubbleText() {
  if (typeof document === "undefined") return null;
  let convo = null;
  try {
    convo = document.getElementById("conversation")
      || document.getElementById("bmo-conversation");
  } catch (_) {
    return null;
  }
  if (!convo) return null;
  let rows = null;
  try { rows = convo.querySelectorAll(".message-row.user"); } catch (_) { return null; }
  if (!rows || !rows.length) return null;
  for (let i = rows.length - 1; i >= 0; i--) {
    const row = rows[i];
    if (!(row instanceof HTMLElement)) continue;
    const bubble = row.querySelector(".bubble");
    if (!(bubble instanceof HTMLElement)) continue;
    if (bubble.classList.contains("interrupt-preview")) continue;
    const txt = (bubble.textContent || "").trim();
    if (txt) return txt;
  }
  return null;
}

/* logTurnTextIntegrity → moved to utils/logging.js (Stage 3, 2026-05-27).
 * window.logTurnTextIntegrity alias is now set inside utils/logging.js. */

/* =========================================================================
 *  WORK MODE — ORIGINAL FULL-COMMAND BUBBLE PRESERVATION
 *  (Stabilization Stage 1.5, 2026-05-27)
 *  ---------------------------------------------------------------------
 *  The Work Mode multi-action planner takes a compound command like
 *  "go to panel 2 and explain the Vietnam War" and dispatches each sub
 *  action through the existing /infer pipeline using the CLEANED segment
 *  text ("explain the Vietnam War"). When that sub-action's server NDJSON
 *  meta arrives, `commitServerUserTranscriptBubble` would normally
 *  overwrite the live user bubble with the cleaned segment, dropping the
 *  navigation half of the user's original phrasing.
 *
 *  This module-scoped "hold" lets the planner's caller pre-seed (or tag)
 *  the bubble with the FULL ORIGINAL TEXT and tell
 *  `commitServerUserTranscriptBubble` to skip any sub-action bubble
 *  overwrite for the duration of the executor.
 *
 *  Strictly UI-side: nothing here changes routing, action execution,
 *  reasoning, checklist, music, news, or close-panel behaviour. The
 *  `[WORKMODE_COMMAND_DISPLAY_TEXT]` log helper is the matching trace.
 * ========================================================================= */

let _veraWorkModeMultiActionBubbleHold = null;
let _veraWorkModeRenderedOriginalBubbleGuard = null;

function _wmNowMs() {
  try { return Date.now(); } catch (_) { return 0; }
}

function _wmHoldOriginalUserBubble(originalFullUserText) {
  _veraWorkModeMultiActionBubbleHold = {
    originalText: String(originalFullUserText || ""),
    startedAt: Date.now(),
  };
}

function _wmReleaseOriginalUserBubbleHold() {
  _veraWorkModeMultiActionBubbleHold = null;
}

function _wmIsOriginalUserBubbleHeld() {
  return _veraWorkModeMultiActionBubbleHold != null;
}

function _wmHeldOriginalUserBubbleText() {
  return _veraWorkModeMultiActionBubbleHold
    ? _veraWorkModeMultiActionBubbleHold.originalText
    : null;
}

/** Normalize for substring-similarity comparison: lowercase, collapse non-word
 *  chars to spaces, trim. Used to confirm that an incoming server transcript
 *  really is a sub-segment of the original full command before suppressing
 *  its bubble overwrite. Prevents an unrelated parallel turn from being
 *  silently dropped on the floor if it ever slips into the hold window. */
function _wmNormalizeForSegmentMatch(s) {
  return String(s || "")
    .toLowerCase()
    .replace(/[^\w]+/g, " ")
    .trim();
}

function _wmCleanExpiredRenderedOriginalGuard() {
  const guard = _veraWorkModeRenderedOriginalBubbleGuard;
  if (!guard) return null;
  const now = _wmNowMs();
  if (guard.expiresAt && now && now > guard.expiresAt) {
    _veraWorkModeRenderedOriginalBubbleGuard = null;
    return null;
  }
  return guard;
}

function _wmMarkOriginalUserBubbleRendered(originalFullUserText, cleanedExecutionTexts = [], source = "") {
  const originalText = String(originalFullUserText || "").trim();
  if (!originalText) return null;
  const cleanedTexts = Array.isArray(cleanedExecutionTexts)
    ? cleanedExecutionTexts
    : [cleanedExecutionTexts];
  const cleanedPrompts = cleanedTexts
    .map((raw) => String(raw || "").trim())
    .filter(Boolean)
    .map((raw) => ({
      raw,
      norm: _wmNormalizeForSegmentMatch(raw),
      suppressedCount: 0,
    }))
    .filter((p) => p.norm);
  const now = _wmNowMs();
  _veraWorkModeRenderedOriginalBubbleGuard = {
    originalText,
    originalNorm: _wmNormalizeForSegmentMatch(originalText),
    cleanedPrompts,
    source,
    startedAt: now,
    expiresAt: now ? now + 45000 : 0,
  };
  return _veraWorkModeRenderedOriginalBubbleGuard;
}

function _wmCleanedExecutionTextsFromPlan(plan) {
  return Array.isArray(plan?.actions)
    ? plan.actions
        .map((a) => String(a?.payload?.prompt || a?.segmentText || "").trim())
        .filter(Boolean)
    : [];
}

function _wmRenderedOriginalGuardText() {
  const guard = _wmCleanExpiredRenderedOriginalGuard();
  return guard ? guard.originalText : null;
}

function _wmSuppressionOriginalUserBubbleText() {
  return _wmHeldOriginalUserBubbleText() || _wmRenderedOriginalGuardText();
}

function _wmIncomingLooksLikeOriginalSegment(incomingText) {
  const original = _wmSuppressionOriginalUserBubbleText();
  if (!original) return false;
  const a = _wmNormalizeForSegmentMatch(original);
  const b = _wmNormalizeForSegmentMatch(incomingText);
  if (!a || !b) return false;
  if (a === b) return true;
  if (a.includes(b)) return true;
  /* Lenient reverse direction so trivial planner re-stitchings still match. */
  if (b.length >= 6 && a.includes(b.slice(0, Math.max(6, Math.floor(b.length * 0.6))))) return true;
  return false;
}

function _wmConsumeDuplicateCleanedPromptGuard(incomingText) {
  const guard = _wmCleanExpiredRenderedOriginalGuard();
  if (!guard) return null;
  const incomingNorm = _wmNormalizeForSegmentMatch(incomingText);
  if (!incomingNorm) return null;
  for (const prompt of guard.cleanedPrompts || []) {
    if (!prompt || !prompt.norm) continue;
    if (prompt.suppressedCount >= 3) continue;
    if (prompt.norm === incomingNorm) {
      prompt.suppressedCount += 1;
      return { originalText: guard.originalText, cleanedText: prompt.raw, source: guard.source };
    }
  }
  return null;
}

function _wmShouldSuppressDuplicateUserBubble(incomingText) {
  if (_wmIsOriginalUserBubbleHeld() && _wmIncomingLooksLikeOriginalSegment(incomingText)) {
    return {
      originalText: _wmSuppressionOriginalUserBubbleText(),
      cleanedText: String(incomingText || "").trim(),
      reason: "active_executor_hold",
    };
  }
  const lateGuardMatch = _wmConsumeDuplicateCleanedPromptGuard(incomingText);
  if (lateGuardMatch) {
    return {
      originalText: lateGuardMatch.originalText,
      cleanedText: lateGuardMatch.cleanedText,
      reason: "rendered_original_guard",
    };
  }
  return null;
}

function _workModeCommandDisplayTextEnabled() {
  try {
    if (typeof window !== "undefined" && window.VERA_DEBUG_WM_DISPLAY === false) return false;
  } catch (_) {}
  return safeGetLocalStorage("VERA_DEBUG_WM_DISPLAY") !== "0";
}

/** Emit a single `[WORKMODE_COMMAND_DISPLAY_TEXT]` line. Strictly diagnostic —
 *  never mutates state. Wrapped in try/catch so a malformed payload can never
 *  break a real turn. */
function logWorkModeCommandDisplayText(fields = {}) {
  if (!_workModeCommandDisplayTextEnabled()) return;
  try {
    const originalFullUserText =
      fields.originalFullUserText != null ? String(fields.originalFullUserText) : null;
    const renderedUserBubbleText =
      fields.renderedUserBubbleText !== undefined
        ? (fields.renderedUserBubbleText == null ? null : String(fields.renderedUserBubbleText))
        : _readLatestUserBubbleText();
    const cleanedExecutionText =
      fields.cleanedExecutionText != null ? String(fields.cleanedExecutionText) : null;
    const eq = (a, b) => {
      if (a == null || b == null) return null;
      return String(a).trim() === String(b).trim();
    };
    const payload = {
      tag: "WORKMODE_COMMAND_DISPLAY_TEXT",
      originalFullUserText,
      cleanedExecutionText,
      renderedUserBubbleText,
      rendered_eq_original: eq(renderedUserBubbleText, originalFullUserText),
      duplicateUserBubbleSuppressed:
        fields.duplicateUserBubbleSuppressed != null
          ? Boolean(fields.duplicateUserBubbleSuppressed)
          : null,
      usedCleanedTextAsInternalPromptOnly:
        fields.usedCleanedTextAsInternalPromptOnly != null
          ? Boolean(fields.usedCleanedTextAsInternalPromptOnly)
          : null,
      commandLooksMultiAction:
        fields.commandLooksMultiAction != null ? Boolean(fields.commandLooksMultiAction) : null,
      source: fields.source || null,
      timestamp: new Date().toISOString(),
    };
    console.info("[WORKMODE_COMMAND_DISPLAY_TEXT]", payload);
  } catch (e) {
    try { console.warn("[WORKMODE_COMMAND_DISPLAY_TEXT] log failed", e); } catch (_) {}
  }
}
try {
  if (typeof window !== "undefined") {
    window.logWorkModeCommandDisplayText = logWorkModeCommandDisplayText;
  }
} catch (_) {}

