const VERA_SETTING_TEXT_GUIDE_ROTATOR_KEY = "vera_setting_text_guide_rotator_v1";
const VERA_SETTING_PLANNING_DEADLINE_TIMER_KEY = "vera_setting_planning_deadline_timer_v1";

