function isFlowModeSidePaneCrossfadeEnabled() {
  try {
    if (appModePrefix() === "vera" && document.getElementById("vera-app")?.classList.contains("work-mode")) {
      return false;
    }
  } catch {}
  return true;
}

/**
 * When the side pane is already visible, swap inner content with a short fade (music ↔ news / finance)
 * so innerHTML replacement does not fight the panel slide-in transition.
 */
function runFlowModeSidePaneContentCrossfade(sidePaneEl, renderCallback) {
  if (
    !sidePaneEl ||
    !isFlowModeSidePaneCrossfadeEnabled() ||
    sidePaneEl.hidden ||
    !sidePaneEl.classList.contains("visible")
  ) {
    renderCallback();
    return;
  }

  let outDone = false;
  let fallbackOut = null;
  const finishOut = () => {
    if (outDone) return;
    outDone = true;
    if (fallbackOut != null) window.clearTimeout(fallbackOut);
    sidePaneEl.removeEventListener("transitionend", onOutEnd);
    renderCallback();
    window.requestAnimationFrame(() => {
      sidePaneEl.classList.remove("side-pane-swap-hiding");
      sidePaneEl.classList.add("side-pane-swap-in");
      let fallbackIn = null;
      function clearIn() {
        if (fallbackIn != null) window.clearTimeout(fallbackIn);
        sidePaneEl.removeEventListener("animationend", onInEnd);
        sidePaneEl.classList.remove("side-pane-swap-in");
      }
      function onInEnd(ev) {
        const n = String(ev.animationName || "");
        if (!n.includes("side-pane-content-swap-in")) return;
        clearIn();
      }
      sidePaneEl.addEventListener("animationend", onInEnd);
      fallbackIn = window.setTimeout(clearIn, 480);
    });
  };

  const onOutEnd = (ev) => {
    if (ev.target !== sidePaneEl) return;
    if (ev.propertyName !== "opacity" && ev.propertyName !== "filter") return;
    finishOut();
  };

  sidePaneEl.classList.add("side-pane-swap-hiding");
  sidePaneEl.addEventListener("transitionend", onOutEnd);
  fallbackOut = window.setTimeout(finishOut, 420);
}

/** NDJSON can call ``applyActionPayload`` from ``finalizeNdjsonStreamingReply`` before first audio and again from ``onPlayStart`` — duplicate Spotify starts / skips twitch the UI. */
function musicPlaybackDedupeKey(payload, op) {
  if (!payload || payload.panel_type !== "music_control") return "";
  if (op === "play_track" && payload.uri) return `play_track:${String(payload.uri).trim()}`;
  if (op === "play_album" && payload.uri) return `play_album:${String(payload.uri).trim()}`;
  if (op === "play_playlist_by_name") {
    const n = String(payload.playlist_name || "").trim().toLowerCase();
    if (n) return `play_playlist_by_name:${n}`;
  }
  if (op === "play_builtin") {
    const p = String(payload.playlist_id || "").trim().toLowerCase();
    const s = String(payload.sound_id || "").trim().toLowerCase();
    if (p) return `play_builtin:pl:${p}`;
    if (s) return `play_builtin:snd:${s}`;
  }
  return "";
}

function isRecentSameMusicPlay(payload, op) {
  const key = musicPlaybackDedupeKey(payload, op);
  if (!key) return false;
  const prev = window.__veraMusicPlaybackDedupe;
  return !!(prev && prev.key === key && performance.now() - prev.at < 7000);
}

/**
 * Collapse NDJSON double ``applyActionPayload`` (finalize + first audio).
 * Applies to non-idempotent music controls only:
 *   - ``skip_next`` / ``skip_previous`` — each call advances/rewinds a track.
 *   - ``volume_delta`` — each call adds ``payload.delta`` to volume, so the
 *     double-dispatch path was actually doubling the user's "turn up / turn
 *     down the music" command (+10% per turn instead of +5%). Keyed by
 *     sign-of-delta so that "volume up then volume down" within the dedupe
 *     window still applies both directions.
 *
 * ``pause`` / ``resume`` are idempotent (calling pause on an already-paused
 * stream is a no-op) so we don't dedupe them.
 *
 * 900 ms window is short enough that legitimate consecutive commands still
 * fire — humans don't realistically issue the same transport command twice
 * within a second.
 */
function shouldApplyMusicTransportAction(payload, op) {
  let key;
  if (op === "skip_next" || op === "skip_previous") {
    key = `music_transport:${op}`;
  } else if (op === "volume_delta") {
    const rawDelta = Number((payload && payload.delta) || 0);
    if (!Number.isFinite(rawDelta) || rawDelta === 0) return true;
    const dir = rawDelta > 0 ? "+1" : "-1";
    key = `music_transport:volume_delta:${dir}`;
  } else {
    return true;
  }
  const now = performance.now();
  const prev = window.__veraMusicTransportDedupe;
  if (prev && prev.key === key && now - prev.at < 900) {
    if (op === "skip_previous") {
      console.log("[MUSIC][SKIP_PREV] dedupe-drop", { delta_ms: Math.round(now - prev.at) });
    } else if (op === "volume_delta") {
      console.log("[MUSIC][VOLUME] dedupe-drop", {
        delta_ms: Math.round(now - prev.at),
        delta: Number((payload && payload.delta) || 0),
      });
    }
    return false;
  }
  window.__veraMusicTransportDedupe = { key, at: now };
  return true;
}

async function invokeSpotifyTransport(op, { source = "unknown" } = {}) {
  const fn =
    op === "skip_previous"
      ? window.VeraSpotify?.skipPrevious
      : op === "skip_next"
      ? window.VeraSpotify?.skipNext
      : null;
  if (typeof fn !== "function") {
    console.log("[MUSIC][TRANSPORT] missing-handler", { op, source });
    return false;
  }
  console.log("[MUSIC][TRANSPORT] invoke", { op, source });
  await Promise.resolve(fn());
  await new Promise((r) => setTimeout(r, 180));
  return true;
}

async function builtinMusicTransportSkipNext(prefix) {
  const st = window.__veraFreeMusicPlayback;
  if (st?.mode === "playlist" && st.queue?.length > 1) {
    const next = ((Number(st.index) || 0) + 1) % st.queue.length;
    await freeMusicPlayQueueIndex(prefix, next);
    return true;
  }
  return false;
}

async function builtinMusicTransportSkipPrevious(prefix) {
  const st = window.__veraFreeMusicPlayback;
  const a = document.getElementById(`${prefix}-free-music-audio`);
  if (st?.mode === "playlist" && st.queue?.length > 1) {
    const pos = Math.round((a?.currentTime || 0) * 1000);
    if (pos > SPOTIFY_PREVIOUS_RESTART_MS && a) {
      a.currentTime = 0;
      freeMusicSyncNowFromAudio(prefix);
      return true;
    }
    const prev = ((Number(st.index) || 0) + st.queue.length - 1) % st.queue.length;
    await freeMusicPlayQueueIndex(prefix, prev);
    return true;
  }
  return false;
}

/** Returns false when the same play was already started a few seconds ago (NDJSON finalize + first-audio both call this). */
function shouldPlayMusicThisInvocation(payload, op) {
  const key = musicPlaybackDedupeKey(payload, op);
  if (!key) return true;
  const now = performance.now();
  const prev = window.__veraMusicPlaybackDedupe;
  if (prev && prev.key === key && now - prev.at < 7000) return false;
  window.__veraMusicPlaybackDedupe = { key, at: now };
  return true;
}

/** NDJSON may invoke ``applyActionPayload`` twice (finalize + first audio) — skip duplicate reasoning ops. */
function workModeReasoningDedupeKey(payload) {
  if (!payload || payload.panel_type !== "work_mode_reasoning") return "";
  const op = String(payload.op || "");
  if (op === "open_new") {
    const requestId = String(payload.panel_open_request_id || payload.new_panel_request_id || "").trim();
    return requestId
      ? `open_new:${requestId}`
      : `open_new:${Math.max(1, Number(payload.count) || 1)}`;
  }
  if (op === "open_and_stream") {
    const requestId = String(payload.new_panel_request_id || payload.panel_open_request_id || "").trim();
    const prompt = String(payload.prompt || "").trim().toLowerCase().slice(0, 120);
    return requestId ? `open_and_stream:${requestId}:${prompt}` : "";
  }
  if (op === "activate" && payload.panel_index != null) {
    return `activate:${Number(payload.panel_index)}`;
  }
  return "";
}

/**
 * Block server-driven reasoning tab activation when the user line refers to homework ordinals
 * ("second problem") rather than UI navigation ("second panel"). Mirrors
 * `should_block_reasoning_panel_activation_for_ordinal_problem` in actions/work_mode_reasoning.py.
 */
function shouldBlockOrdinalProblemLaneActivation(userText) {
  const s = String(userText || "").trim();
  if (!s) return false;
  const low = s.toLowerCase();
  if (/\b(?:reasoning\s+)?(?:panel|tab|lane)\b/i.test(low)) return false;
  if (/\breasoning\s+space\b/i.test(low)) return false;
  if (
    /\b(?:go\s+back\s+to|go\s+to|jump\s+to|switch\s+to|change\s+to|open|activate|show|select|use)\b[^.?!]{0,96}\b(?:reasoning\s+)?(?:panel|tab|lane|page)\b/i.test(
      low
    )
  ) {
    return false;
  }
  if (
    /\b(?:first|second|third|fourth|fifth|sixth|seventh|eighth|next|previous|last|prior)\s+(?:reasoning\s+)?(?:panel|tab|lane|page)\b/i.test(
      low
    )
  ) {
    return false;
  }
  if (/\b(?:panel|tab)\s*#?\s*\d{1,2}\b/i.test(low)) return false;
  if (
    /\b(?:first|second|third|fourth|fifth|next|previous|last|prior|other|another)\s+(?:problem|question|part|exercise)\b/i.test(
      low
    )
  ) {
    return true;
  }
  if (/\b(?:next|another)\s+(?:problem|question|part)\b/i.test(low)) return true;
  if (/\bproblem\s*(?:#|no\.?|number\s*)?\s*\d/i.test(low)) return true;
  if (/\bproblem\s*(?:#|no\.?)?\s*\d+\.\d+/i.test(low)) return true;
  if (/\b(?:ex\.?|exercise|question|q)\s*[#.]?\s*\d+/i.test(low)) return true;
  if (/\bthe\s+other\s+(?:problem|question|part)\b/i.test(low)) return true;
  if (
    /\b(?:this|that|the)\s+assignment(?:'s|s)?\s+(?:first|second|third|fourth|next|last)\s+part\b/i.test(
      low
    )
  ) {
    return true;
  }
  if (/\bpart\s*\d+\b/i.test(low)) return true;
  return false;
}

function inferUserTextForLaneActivationGuard(data) {
  return String(
    data?.transcript || (typeof window !== "undefined" && window.__veraLastInferUserTextForLaneGuard) || ""
  ).trim();
}

function shouldApplyWorkModeReasoningInvocation(payload) {
  const key = workModeReasoningDedupeKey(payload);
  if (!key) return true;
  const now = performance.now();
  const prev = window.__veraWorkModeReasoningDedupe;
  if (prev && prev.key === key && now - prev.at < 8000) return false;
  window.__veraWorkModeReasoningDedupe = { key, at: now };
  return true;
}

/**
 * Source-state tracker. Single source of truth for which music backend is
 * currently audible vs. paused-on-purpose vs. suspended-because-the-other-
 * source-took-over. The model matches the spec from 2026-05-29:
 *
 *   activeMusicSource   "builtin" | "spotify" | "none"
 *   builtinState        "playing" | "paused_by_user" | "suspended_for_spotify" | "stopped"
 *   spotifyState        "playing" | "paused_by_user" | "suspended_for_builtin" | "stopped"
 *
 * Crucial invariant: pause/stop for ONE source NEVER auto-resumes the
 * other. Suspended state is preserved across switches so an explicit
 * "play lo-fi" / "resume Spotify" can restore the prior position when
 * the user asks for it.
 */
function veraMusicSourceState() {
  if (!window.__veraMusicSourceState) {
    window.__veraMusicSourceState = {
      active: "none",
      builtin: {
        state: "stopped",
        currentTime: 0,
        playlistId: "",
        soundId: "",
        // Display fields kept independent of the live audio element so the
        // built-in tab can re-render its last known item even when Spotify
        // is the currently audible source.
        title: "",
        subtitle: "",
        cover_url: "",
        paused: true,
        position_ms: 0,
        duration_ms: 0,
        updatedAt: 0
      },
      spotify: {
        state: "stopped",
        uri: "",
        title: "",
        artist: "",
        playlist_id: "",
        playlist_name: "",
        cover_url: "",
        paused: true,
        position_ms: 0,
        duration_ms: 0,
        updatedAt: 0
      }
    };
  }
  const st = window.__veraMusicSourceState;
  // Backfill new fields on existing state objects so older sessions don't
  // miss the display sub-fields after a code update.
  if (st.builtin && st.builtin.title === undefined) {
    Object.assign(st.builtin, {
      title: "", subtitle: "", cover_url: "", paused: true,
      position_ms: 0, duration_ms: 0, updatedAt: 0
    });
  }
  if (st.spotify && st.spotify.cover_url === undefined) {
    Object.assign(st.spotify, {
      cover_url: "", paused: true, position_ms: 0, duration_ms: 0, updatedAt: 0
    });
  }
  return st;
}

/**
 * Update one source's UI display snapshot without touching the other.
 *
 * The music panel needs to remember what each tab was last showing
 * independently of which source is currently audible, so e.g. switching
 * to the Spotify tab after lo-fi was playing still shows the previous
 * Spotify track instead of "Nothing playing".
 *
 * Call this from whichever path actually changed the source's state —
 * builtin sync from the audio element, Spotify state from the Web SDK
 * or from a play call. Safe to call with partial updates.
 */
function captureMusicPanelDisplay(source, partial) {
  if (!partial || typeof partial !== "object") return;
  const st = veraMusicSourceState();
  let target = null;
  if (source === "builtin") target = st.builtin;
  else if (source === "spotify") target = st.spotify;
  if (!target) return;
  for (const key of Object.keys(partial)) {
    if (partial[key] === undefined) continue;
    target[key] = partial[key];
  }
  target.updatedAt = Date.now();
}

function veraMusicPanelDisplayHasData(source) {
  const st = veraMusicSourceState();
  const snap = source === "builtin" ? st.builtin : (source === "spotify" ? st.spotify : null);
  if (!snap) return false;
  return Boolean((snap.title || "").trim()) || Number(snap.updatedAt || 0) > 0;
}

function _captureBuiltinSnapshot() {
  const prefix = (typeof appModePrefix === "function") ? appModePrefix() : "vera";
  const free = document.getElementById(`${prefix}-free-music-audio`);
  const pb = window.__veraFreeMusicPlayback || {};
  return {
    currentTime: Number(free?.currentTime || 0),
    playlistId: String(pb.playlistId || ""),
    soundId: String(pb.soundId || ""),
    isPlaying: Boolean(free && !free.paused && Number(free.currentTime) > 0)
  };
}

function _captureSpotifySnapshot() {
  const last = window.__veraSpotifyLast || {};
  let isPlaying = false;
  try {
    const ns = (typeof spotifyEnsureNowState === "function") ? spotifyEnsureNowState() : null;
    if (ns) isPlaying = Boolean(ns.active) && !Boolean(ns.paused);
  } catch (_) {}
  return {
    uri: String(last.preview_url ? "" : (last.uri || "")) || "",
    title: String(last.title || ""),
    artist: String(last.artist || ""),
    playlist_id: String(window.__veraSpotifyActivePlaylistId || ""),
    playlist_name: String(window.__veraSpotifyActivePlaylistName || ""),
    isPlaying
  };
}

function musicSourceMarkPlaying(source, meta = {}) {
  const st = veraMusicSourceState();
  const newSource = String(source || "").toLowerCase();
  const activeBefore = st.active;
  const builtinStateBefore = st.builtin.state;
  const spotifyStateBefore = st.spotify.state;
  if (newSource === "builtin") {
    const priorBuiltinState = st.builtin.state;
    const priorBuiltinCurrentTime = Number(st.builtin.currentTime || 0);
    // Suspend Spotify if it was the active audible source — preserve its
    // metadata so an explicit "resume Spotify" can return to it.
    if (st.active === "spotify" && st.spotify.state === "playing") {
      st.spotify.state = "suspended_for_builtin";
    }
    st.active = "builtin";
    st.builtin.state = "playing";
    if (meta.playlistId !== undefined) st.builtin.playlistId = String(meta.playlistId || "");
    if (meta.soundId !== undefined) st.builtin.soundId = String(meta.soundId || "");
    if (meta.title !== undefined) st.builtin.title = String(meta.title || "");
    if (meta.subtitle !== undefined) st.builtin.subtitle = String(meta.subtitle || "");
    if (meta.currentTime !== undefined) {
      st.builtin.currentTime = Number(meta.currentTime || 0);
    } else if (priorBuiltinState === "suspended_for_spotify") {
      st.builtin.currentTime = priorBuiltinCurrentTime;
    } else {
      st.builtin.currentTime = 0;
    }
    st.builtin.paused = false;
    st.builtin.updatedAt = Date.now();
  } else if (newSource === "spotify") {
    if (st.active === "builtin" && st.builtin.state === "playing") {
      // Snapshot the current audio position before suspending so explicit
      // "play lo-fi" later can resume from the same spot when possible.
      const snap = _captureBuiltinSnapshot();
      st.builtin.state = "suspended_for_spotify";
      st.builtin.currentTime = snap.currentTime;
      st.builtin.paused = true;
    }
    st.active = "spotify";
    st.spotify.state = "playing";
    if (meta.uri !== undefined) st.spotify.uri = String(meta.uri || "");
    if (meta.title !== undefined) st.spotify.title = String(meta.title || "");
    if (meta.artist !== undefined) st.spotify.artist = String(meta.artist || "");
    if (meta.playlist_id !== undefined) st.spotify.playlist_id = String(meta.playlist_id || "");
    if (meta.playlist_name !== undefined) st.spotify.playlist_name = String(meta.playlist_name || "");
    if (meta.playlist_id) window.__veraSpotifyActivePlaylistId = String(meta.playlist_id || "");
    if (meta.playlist_name) window.__veraSpotifyActivePlaylistName = String(meta.playlist_name || "");
    st.spotify.paused = false;
    st.spotify.updatedAt = Date.now();
  }
  console.info("[music_source_state]", {
    transition: `${newSource}_play`,
    playback_source_changed: activeBefore !== st.active,
    playback_source_change_reason: meta.reason || "explicit_play",
    active_playback_source_before: activeBefore,
    active_playback_source_after: st.active,
    builtin_state_before: builtinStateBefore,
    builtin_state_after: st.builtin.state,
    builtin_title: st.builtin.title || "",
    builtin_current_time_preserved: st.builtin.state === "suspended_for_spotify"
      ? Number(st.builtin.currentTime || 0)
      : null,
    spotify_state_before: spotifyStateBefore,
    spotify_state_after: st.spotify.state,
    spotify_title: st.spotify.title || "",
    spotify_artist: st.spotify.artist || "",
    spotify_uri: st.spotify.uri || ""
  });
}

function musicSourceMarkPausedByUser() {
  // Generic "pause music" — pause whichever source is currently active and
  // mark it paused_by_user. Do NOT touch the suspended-source state: that
  // way "pause music" after a builtin→spotify switch stops audio without
  // accidentally resurrecting built-in lo-fi.
  const st = veraMusicSourceState();
  const prev = st.active;
  const builtinStateBefore = st.builtin.state;
  const spotifyStateBefore = st.spotify.state;
  if (prev === "builtin" && st.builtin.state === "playing") {
    st.builtin.state = "paused_by_user";
    st.builtin.paused = true;
  }
  if (prev === "spotify" && st.spotify.state === "playing") {
    st.spotify.state = "paused_by_user";
    st.spotify.paused = true;
  }
  st.active = "none";
  console.info("[music_source_state]", {
    transition: "pause_by_user",
    playback_source_changed: prev !== "none",
    playback_source_change_reason: "user_pause",
    active_playback_source_before: prev,
    active_playback_source_after: st.active,
    builtin_state_before: builtinStateBefore,
    builtin_state_after: st.builtin.state,
    builtin_title: st.builtin.title || "",
    spotify_state_before: spotifyStateBefore,
    spotify_state_after: st.spotify.state,
    spotify_title: st.spotify.title || "",
    spotify_artist: st.spotify.artist || "",
    spotify_paused_without_builtin_resume: prev === "spotify",
    blocked_auto_resume_reason:
      prev === "spotify" && st.builtin.state === "suspended_for_spotify"
        ? "spotify_paused_keep_builtin_suspended"
        : prev === "builtin" && st.spotify.state === "suspended_for_builtin"
          ? "builtin_paused_keep_spotify_suspended"
          : null
  });
}

/**
 * Stop whichever music source is currently audible before starting a new
 * one. Built-in `<audio>` elements and Spotify Web Playback can each be
 * playing independently — if a "play" payload arrives while another
 * source is active, the new track must take over instead of layering.
 *
 * source describes the NEW playback we're about to start:
 *   "builtin" → free-music audio element (lo-fi, rain, noise, etc.)
 *   "spotify" → Spotify track / album / playlist via VeraSpotify
 *   "unknown" → caller doesn't know yet; pause everything
 *
 * Always safe to call: never raises, never starts new playback, only
 * pauses what's already running.
 */
function stopCurrentMusicPlaybackBeforeNewPlay(source) {
  const newSource = String(source || "unknown").toLowerCase();
  const prefix = (typeof appModePrefix === "function") ? appModePrefix() : "vera";
  const free = document.getElementById(`${prefix}-free-music-audio`);
  const st = veraMusicSourceState();
  const activeBefore = st.active;
  const builtinStateBefore = st.builtin.state;
  const spotifyStateBefore = st.spotify.state;
  const builtinWasPlaying = Boolean(free && !free.paused && free.currentTime > 0);
  let spotifyWasPlaying = false;
  try {
    const ns = (typeof spotifyEnsureNowState === "function") ? spotifyEnsureNowState() : null;
    if (ns && Boolean(ns.active) && !Boolean(ns.paused)) {
      spotifyWasPlaying = true;
    }
  } catch (_) { /* getter may not exist on older builds */ }

  // Snapshot currentTime of built-in audio BEFORE we pause it so the
  // suspended-state preserves "where we were" for a later explicit
  // resume ("play lo-fi" after switching to Spotify and back).
  const builtinSnap = _captureBuiltinSnapshot();

  console.info("[music_dispatch]", {
    stop_current_music_before_new_play_called: true,
    new_source: newSource,
    builtin_music_was_playing: builtinWasPlaying,
    spotify_was_playing: spotifyWasPlaying,
    active_music_source_before: activeBefore,
    builtin_state_before: builtinStateBefore,
    spotify_state_before: spotifyStateBefore,
    builtin_current_time_preserved: builtinSnap.currentTime
  });

  let builtinStopped = false;
  let spotifyStopped = false;
  try {
    if (free && !free.paused) {
      musicPlaybackDiag("[builtin_pause_called]", {
        reason: `stop_before_${newSource}`,
        source: "stopCurrentMusicPlaybackBeforeNewPlay",
        prefix,
      });
      free.pause();
      builtinStopped = true;
      if (typeof freeMusicSyncNowFromAudio === "function") freeMusicSyncNowFromAudio(prefix);
      if (typeof spotifySyncPlayButtonUi === "function") spotifySyncPlayButtonUi(prefix);
      // If we're switching to Spotify, mark built-in suspended (state may
      // be restored by an explicit "play lo-fi"). Switching to built-in
      // again with a fresh play is a no-op as the new play resets state.
      if (newSource === "spotify") {
        st.builtin.state = "suspended_for_spotify";
        st.builtin.currentTime = builtinSnap.currentTime;
        st.builtin.playlistId = builtinSnap.playlistId;
        st.builtin.soundId = builtinSnap.soundId;
      }
    }
  } catch (err) {
    console.warn("[music_dispatch] builtin_pause_failed", err);
  }
  try {
    const pause = window.VeraSpotify && window.VeraSpotify.pausePlayback;
    if (typeof pause === "function" && (spotifyWasPlaying || newSource === "builtin")) {
      musicPlaybackDiag("[spotify_pause_called]", {
        reason: `stop_before_${newSource}`,
        source: "stopCurrentMusicPlaybackBeforeNewPlay",
        prefix,
      });
      // Pause Spotify whenever we're switching TO built-in. When switching
      // between Spotify tracks (play_track / play_album) Spotify itself
      // replaces the current track on the next play call, so an explicit
      // pause is only required when crossing the source boundary.
      void pause();
      spotifyStopped = true;
      if (newSource === "builtin" && spotifyWasPlaying) {
        st.spotify.state = "suspended_for_builtin";
      }
    }
  } catch (err) {
    console.warn("[music_dispatch] spotify_pause_failed", err);
  }
  console.info("[music_dispatch]", {
    new_source: newSource,
    builtin_music_stopped: builtinStopped,
    spotify_playback_stopped: spotifyStopped,
    active_music_source_after: st.active,
    builtin_state_after: st.builtin.state,
    spotify_state_after: st.spotify.state,
    builtin_suspended_for_spotify: st.builtin.state === "suspended_for_spotify",
    spotify_suspended_for_builtin: st.spotify.state === "suspended_for_builtin",
    builtin_auto_resume_blocked: true,
    spotify_auto_resume_blocked: true
  });
}

const VERA_NDJSON_PAYLOAD_DEDUPE_TTL_MS = 30000;

function veraNdjsonPayloadDedupeStore() {
  if (!window.__veraNdjsonPayloadDedupe || !(window.__veraNdjsonPayloadDedupe instanceof Map)) {
    window.__veraNdjsonPayloadDedupe = new Map();
  }
  return window.__veraNdjsonPayloadDedupe;
}

function makeNdjsonPayloadDedupeKey(event, payload, index) {
  const req =
    event?.request_id ||
    event?.client_request_id ||
    event?.requestId ||
    event?.session_id ||
    "no_request";
  const type = payload?.panel_type || payload?.type || "unknown_payload";
  const op = payload?.op || payload?.action || payload?.action_name || "no_op";
  const planId = String(payload?.action_plan_id || "").trim() || "noplan";
  const seqIdx = Number.isFinite(Number(payload?.planner_action_index))
    ? Number(payload.planner_action_index)
    : Number(index) || 0;
  if (type === "music_control" && op) {
    const target = String(
      payload?.uri ||
        payload?.playlist_name ||
        payload?.query ||
        payload?.playlist_id ||
        payload?.sound_id ||
        ""
    ).slice(0, 120);
    return `${req}:${planId}:${seqIdx}:${type}:${op}:${target}`;
  }
  return `${req}:${planId}:${seqIdx}:${type}:${op}`;
}

async function applyNdjsonActionPayloadEvent(event, ndjsonEventType = "unknown") {
  const plural = Array.isArray(event?.action_payloads)
    ? event.action_payloads.filter(Boolean)
    : [];
  const payloads = plural.length ? plural : (event?.action_payload ? [event.action_payload] : []);
  const store = veraNdjsonPayloadDedupeStore();
  const now = Date.now();
  for (const [key, at] of store.entries()) {
    if (now - Number(at || 0) > VERA_NDJSON_PAYLOAD_DEDUPE_TTL_MS) store.delete(key);
  }

  console.info("[ndjson_payload_apply]", {
    ndjson_event_type: ndjsonEventType,
    action_payloads_received_count: payloads.length,
    used_plural_payloads: plural.length > 0,
    action_type: event?.action_type || "",
    request_id: event?.request_id || null
  });

  const deduped = [];
  for (let idx = 0; idx < payloads.length; idx++) {
    const payload = payloads[idx];
    if (!payload || typeof payload !== "object") continue;
    const key = makeNdjsonPayloadDedupeKey(event, payload, idx);
    const panelType = payload.panel_type || payload.type || "";
    const op = payload.op || "";
    const duplicate = store.has(key);
    console.info("[ndjson_payload_apply]", {
      ndjson_event_type: ndjsonEventType,
      applying_payload_index: idx,
      applying_payload_type: panelType,
      payload_op: op,
      dedupe_payload_key: key,
      skipped_duplicate_payload: duplicate,
      music_control_received: panelType === "music_control"
    });
    if (duplicate) continue;
    store.set(key, now);
    deduped.push(payload);
  }

  if (deduped.length > 1 && typeof window.veraApplyActionPayloadsInOrder === "function") {
    await window.veraApplyActionPayloadsInOrder(
      deduped,
      (payload, ctx) =>
        applyActionPayload({ ...event, action_payload: payload, action_payloads: null }, ctx),
      { requestId: event?.request_id || null, source: ndjsonEventType }
    );
    return;
  }

  for (let idx = 0; idx < deduped.length; idx++) {
    await applyActionPayload(
      { ...event, action_payload: deduped[idx], action_payloads: null },
      { orderIndex: idx, source: ndjsonEventType }
    );
  }
}

/**
 * 2026-05-29 spec PART 3 — handle the backend planner's
 * ``work_mode_reasoning open_and_stream`` payload.
 *
 * The backend ``reasoning.request`` direct dispatcher emits:
 *   {
 *     panel_type: "work_mode_reasoning",
 *     op: "open_and_stream",
 *     prompt: <clean reasoning span — no music/panel/timer/checklist tokens>,
 *     target_panel_index_1based: <int|null>,
 *     target_panel_index_0based: <int|null>,
 *     target_panel_title: <string|null>,
 *     title_hint: <string|null>,
 *   }
 *
 * We:
 *   1) Activate (or open) the target panel.
 *   2) Submit the clean prompt as a typed Work Mode turn so the existing
 *      reasoning-lane machinery (lane bucket, NDJSON stream, panel
 *      rendering) takes over with NO change. The recursive turn passes
 *      ``__skipMultiActionPlanner`` so the backend planner won't fire
 *      again.
 *   3) Log [reasoning_open_and_stream_payload_received] and, when the
 *      clean prompt still contains music/panel/timer/checklist phrases,
 *      log a [reasoning_prompt_contaminated_by_app_action] hard warning.
 */
function applyWorkModeReasoningOpenAndStreamPayload(payload, data) {
  const promptClean = String(payload?.prompt || "").trim();
  const tgt0 = Number(payload?.target_panel_index_0based);
  let resolvedIdx0 = Number.isFinite(tgt0) ? tgt0 : null;
  if (resolvedIdx0 == null) {
    const tgt1 = Number(payload?.target_panel_index_1based);
    if (Number.isFinite(tgt1) && tgt1 >= 1) resolvedIdx0 = tgt1 - 1;
  }
  const titleHint = String(payload?.title_hint || "").trim();
  let target1based = Number.isFinite(Number(payload?.target_panel_index_1based))
    ? Number(payload.target_panel_index_1based)
    : (Number.isFinite(resolvedIdx0) ? resolvedIdx0 + 1 : null);
  const wantsNewPanel =
    payload?.target_panel === "new" ||
    payload?.target_new_panel === true ||
    String(payload?.target_panel || "").toLowerCase() === "new";
  const newPanelRequestId = String(payload?.new_panel_request_id || payload?.panel_open_request_id || "").trim();
  const actionPlanId = String(payload?.action_plan_id || "").trim();
  /* 2026-06-12 — the user gave an explicit panel destination ("... in
     panel N", "... in a new panel"). The recursive reasoning turn must be
     FORCED into the reasoning panel even if the bare task ("explain
     tennis") would otherwise qualify as a simple Voice-UI answer. */
  const explicitPanelDestination = payload?.explicit_panel_destination === true;

  /* Hard warning: a contaminated prompt would let the reasoning model see
     "play lo-fi" or "go to panel 2" — which would either produce a noisy
     explanation or silently execute the wrong thing. */
  const contamination = [];
  if (promptClean) {
    const lowP = promptClean.toLowerCase();
    if (/\bplay\s+(?:the\s+)?lo[-\s]?fi/.test(lowP)) contamination.push("play_lofi");
    if (/\bpause\s+(?:the\s+)?music/.test(lowP)) contamination.push("pause_music");
    if (/\bset\s+(?:a\s+)?timer/.test(lowP)) contamination.push("set_timer");
    if (/\bchecklist\b/.test(lowP)) contamination.push("checklist");
    if (/\bgo\s+to\s+(?:the\s+)?(?:reasoning\s+)?panel\b/.test(lowP)) contamination.push("go_to_panel");
  }
  if (contamination.length) {
    try {
      console.warn("[reasoning_prompt_contaminated_by_app_action]", {
        reasoning_stream_prompt: promptClean.slice(0, 240),
        contamination_markers: contamination,
        source: "frontend_open_and_stream_dispatcher",
      });
    } catch (_) {}
  }

  const panelsRoot = document.getElementById("vera-reasoning-tab-panels");
  const beforeOrder = (typeof getReasoningPanelOrder === "function") ? getReasoningPanelOrder() : [];
  const activeBefore = beforeOrder.find((p) => p?.tabIndex != null && document.querySelector(`#vera-reasoning-tab-panels .vera-reasoning-tab-panel[data-tab-index="${p.tabIndex}"]`)?.classList.contains("is-active")) || null;
  let activatedPanelLaneId = "";
  try {
    console.info("[active_panel_before_action]", {
      op: "open_and_stream",
      prompt_preview: promptClean.slice(0, 160),
      active_panel_before: activeBefore?.laneId || null,
      target_panel: wantsNewPanel ? "new" : target1based,
      panel_open_request_id: newPanelRequestId || null,
      action_plan_id: actionPlanId || null,
    });
  } catch (_) {}

  if (wantsNewPanel && typeof getValidRecentlyOpenedReasoningPanel === "function") {
    let recent = null;
    try { recent = getValidRecentlyOpenedReasoningPanel(); } catch (_) { recent = null; }
    const recentRequestId = String(recent?.requestId || "").trim();
    const requestMatches =
      Boolean(recent) &&
      (!newPanelRequestId || !recentRequestId || recentRequestId === newPanelRequestId);
    if (requestMatches) {
      resolvedIdx0 = Number(recent.tabIndex);
      activatedPanelLaneId = String(recent.laneId || "");
      const currentOrderForRecent = (typeof getReasoningPanelOrder === "function") ? getReasoningPanelOrder() : [];
      const recentInOrder = Array.isArray(currentOrderForRecent)
        ? currentOrderForRecent.find((p) =>
            String(p?.laneId || "").trim() === activatedPanelLaneId ||
            Number(p?.tabIndex) === Number(resolvedIdx0)
          )
        : null;
      target1based = Number.isFinite(Number(recentInOrder?.visualIndex))
        ? Number(recentInOrder.visualIndex)
        : target1based;
      try {
        if (typeof consumeRecentlyOpenedReasoningPanel === "function") {
          consumeRecentlyOpenedReasoningPanel("planner_open_and_stream_new_panel_target");
        }
      } catch (_) {}
      try {
        console.info("[reasoning_target_panel]", {
          target_panel: "new",
          resolved_panel_id: activatedPanelLaneId || null,
          resolved_tab_index: resolvedIdx0,
          resolved_visual_index_1based: target1based,
          panel_open_request_id: newPanelRequestId || null,
          action_plan_id: actionPlanId || null,
          source: "recently_opened_panel",
        });
      } catch (_) {}
    } else {
      try {
        console.warn("[reasoning_target_panel]", {
          target_panel: "new",
          resolved_panel_id: null,
          panel_open_request_id: newPanelRequestId || null,
          recent_panel_request_id: recentRequestId || null,
          action_plan_id: actionPlanId || null,
          reason: recent ? "recent_panel_request_mismatch" : "no_recent_panel",
        });
      } catch (_) {}
      try {
        console.warn("[panel_target_missing]", {
          target_panel: "new",
          prompt_preview: promptClean.slice(0, 160),
          panel_open_request_id: newPanelRequestId || null,
          action_plan_id: actionPlanId || null,
          recent_panel_request_id: recentRequestId || null,
          reason: recent ? "recent_panel_request_mismatch" : "no_recent_panel",
          source: "open_and_stream_dispatcher",
        });
      } catch (_) {}
      return;
    }
  }

  /* Activate or open the target panel. If the requested index doesn't
     exist yet (e.g. user asked for Panel 4 but only Panel 1-2 are open),
     create extra panels until the index is reachable. ``addReasoningTab``
     enforces ``REASONING_TABS_MAX`` so we can't open more than the limit. */
  if (panelsRoot && resolvedIdx0 == null && !wantsNewPanel && typeof getActiveReasoningLaneIndex === "function") {
    const activeIdx = getActiveReasoningLaneIndex();
    if (Number.isFinite(activeIdx) && activeIdx >= 0) {
      resolvedIdx0 = activeIdx;
      target1based = activeIdx + 1;
    }
  }
  if (panelsRoot && resolvedIdx0 != null) {
    let panelEl = panelsRoot.querySelector(
      `.vera-reasoning-tab-panel[data-tab-index="${resolvedIdx0}"]`
    );
    while (!panelEl && typeof addReasoningTab === "function") {
      const opened = addReasoningTab({ source: "planner_reasoning_request_open_and_stream" });
      if (!opened) break;
      panelEl = panelsRoot.querySelector(
        `.vera-reasoning-tab-panel[data-tab-index="${resolvedIdx0}"]`
      );
      if (!panelEl) {
        const allPanels = panelsRoot.querySelectorAll(".vera-reasoning-tab-panel");
        if (allPanels.length >= 8) break;
      }
    }
    if (panelEl && typeof activateReasoningTab === "function") {
      activateReasoningTab(resolvedIdx0, {
        commandText: promptClean,
        requestedIndex: target1based || (resolvedIdx0 + 1),
        resolvedFrom: "planner_reasoning_request_open_and_stream",
      });
      activatedPanelLaneId = String(panelEl.dataset.laneId || activatedPanelLaneId || "");
    }
  }

  try {
    const finalSelectedPanelId = getActiveDomReasoningLaneId() || null;
    console.info("[final_selected_panel]", {
      stage: "after_open_and_stream_activate",
      prompt_preview: promptClean.slice(0, 160),
      created_or_target_panel_id: activatedPanelLaneId || null,
      final_selected_panel_id: finalSelectedPanelId,
      target_panel_index_1based: target1based,
      target_panel_index_0based: resolvedIdx0,
      panel_open_request_id: newPanelRequestId || null,
      action_plan_id: actionPlanId || null,
    });
    if (activatedPanelLaneId && finalSelectedPanelId && activatedPanelLaneId !== finalSelectedPanelId) {
      console.warn("[panel_target_mismatch]", {
        stage: "after_open_and_stream_activate",
        expected_panel_id: activatedPanelLaneId,
        actual_selected_panel_id: finalSelectedPanelId,
        panel_open_request_id: newPanelRequestId || null,
        action_plan_id: actionPlanId || null,
      });
    }
  } catch (_) {}

  try {
    console.info("[reasoning_open_and_stream_payload_received]", {
      prompt_preview: promptClean.slice(0, 160),
      title_hint: titleHint,
      target_panel_index_1based: target1based,
      target_panel_index_0based: resolvedIdx0,
      target_panel_title: payload?.target_panel_title || null,
      target_panel: wantsNewPanel ? "new" : null,
      panel_open_request_id: newPanelRequestId || null,
      action_plan_id: actionPlanId || null,
      active_panel_before: activeBefore?.laneId || null,
      active_panel_after_activate: activatedPanelLaneId || (activeBefore?.laneId || null),
      contamination_markers: contamination,
    });
  } catch (_) {}

  if (!promptClean) return;

  /* Submit the clean prompt as a typed Work Mode turn — fire-and-forget.
     The recursive turn:
       - sees a single-action utterance ("explain the Vietnam War"), so
         the backend planner gate stays cold,
       - triggers the existing reasoning gate (broad_complex_topic or
         explicit_artifact) which calls /work_mode/reasoning_stream with
         the cleaned span only,
       - lands the streamed answer in the active reasoning panel (which
         we just activated, when a target was supplied). */
  if (typeof sendVeraWorkModeTypedInferTurn === "function") {
    try {
      if (explicitPanelDestination) {
        try {
          console.info("[routing_override]", {
            reason: "explicit_panel_destination_forces_reasoning_panel",
            content_task: promptClean.slice(0, 160),
            target_panel_index_1based: Number.isFinite(target1based) ? target1based : null,
            target_panel: wantsNewPanel ? "new" : (target1based ?? "active"),
            panel_open_request_id: newPanelRequestId || null,
            action_plan_id: actionPlanId || null,
          });
        } catch (_) {}
      }
      void sendVeraWorkModeTypedInferTurn(promptClean, {
        path: "wm-multi-action:reasoning.request.open_and_stream",
        __skipMultiActionPlanner: true,
        /* Explicit panel destination overrides the simple-chat shortcut:
           force the recursive turn's reasoning gate to route to the panel. */
        __reasoningGateForceRoute: explicitPanelDestination ? "reasoning_panel" : undefined,
        __reasoningGateReason: explicitPanelDestination ? "explicit_panel_destination" : undefined,
        __reasoningGateResolvedTopic: explicitPanelDestination ? promptClean : undefined,
        __explicitPanelDestinationConsumed: explicitPanelDestination,
        /* 2026-06-01 — thread the explicit target panel into the recursive
           turn so the reasoning prep's lane acquisition cannot drift onto
           a different panel between the activate-tab call above and the
           recursive ``maybePrepareWorkModeReasoning`` run. The cleaned
           prompt has had the "in panel N" suffix stripped, so without
           this hint we would lose the planner's target signal and the
           lane would fall back to ``getActiveReasoningLaneIndex()``. */
        __reasoningGateTargetPanel: Number.isFinite(target1based) ? target1based : null,
        __voiceToPanelOriginalText: String(
          payload?.original_user_text || data?.transcript || data?.user_text || ""
        ).trim(),
        __voiceToPanelResolvedReferent:
          detectVoiceToPanelDeictic(promptClean) || detectVoiceToPanelActionReference(promptClean)
            ? resolveReasoningPanelTopicFromContext() || null
            : null,
        __voiceToPanelNewPanel: Boolean(wantsNewPanel)
      });
      try {
        console.info("[reasoning_stream_called]", {
          reasoning_stream_called: true,
          reasoning_stream_prompt: promptClean.slice(0, 240),
          reasoning_target_panel: target1based,
          reasoning_target_panel_id: activatedPanelLaneId || null,
          active_panel_after: activatedPanelLaneId || (activeBefore?.laneId || null),
          panel_open_request_id: newPanelRequestId || null,
          action_plan_id: actionPlanId || null,
          source: "open_and_stream_dispatcher",
        });
        console.info("[reasoning_stream_panel]", {
          prompt_preview: promptClean.slice(0, 160),
          target_panel_index_1based: target1based,
          target_panel_id: activatedPanelLaneId || null,
          panel_open_request_id: newPanelRequestId || null,
          action_plan_id: actionPlanId || null,
          source: "open_and_stream_dispatcher",
        });
      } catch (_) {}
    } catch (e) {
      try {
        console.warn("[reasoning_open_and_stream_dispatch_error]", {
          error: String(e?.message || e || "").slice(0, 200),
        });
      } catch (_) {}
    }
  }
}


async function applyMusicControlPayloadAsync(payload, data, seqCtx = {}) {
  const prefix = appModePrefix();
  const op = payload.op || "open_panel";
  console.info("[music_control_payload]", {
    music_control_received: true,
    op,
    playlist_id: payload.playlist_id || "",
    sound_id: payload.sound_id || "",
    source_event_type: data?.type || "",
    request_id: data?.request_id || null,
    sequence_active_provider: seqCtx?.activeProvider || window.__veraMusicSequenceActiveProvider || null,
  });
  if (op === "close_panel") {
    hideSidePanel();
    return;
  }
  const transportProvider = resolveMusicTransportProvider(prefix, seqCtx);
  if (op === "skip_next") {
    if (!shouldApplyMusicTransportAction(payload, op)) return;
    console.warn("[music_transport_route]", {
      op,
      transportProvider,
      uiTab: getProductivityMusicSource(prefix),
      sequenceActiveProvider: seqCtx?.activeProvider || null,
    });
    if (transportProvider === "builtin") {
      await builtinMusicTransportSkipNext(prefix);
      return { op, transportProvider };
    }
    await invokeSpotifyTransport("skip_next", { source: "command" });
    return { op, transportProvider: "spotify" };
  }
  if (op === "skip_previous") {
    if (!shouldApplyMusicTransportAction(payload, op)) return;
    console.log("[MUSIC][SKIP_PREV] applyActionPayload dispatch", {
      source: data?.type || "unknown",
      has_payload: Boolean(payload),
      transportProvider,
    });
    if (transportProvider === "builtin") {
      await builtinMusicTransportSkipPrevious(prefix);
      return { op, transportProvider };
    }
    await invokeSpotifyTransport("skip_previous", { source: "command" });
    return { op, transportProvider: "spotify" };
  }
  if (op === "pause") {
    const activeForPause = resolveMusicTransportProvider(prefix, seqCtx);
    const free = document.getElementById(`${prefix}-free-music-audio`);
    musicPlaybackDiag("[music_pause_called]", {
      reason: "voice_command_pause",
      source: "applyMusicControlPayload",
      prefix,
      transport_provider: activeForPause,
    });
    if (activeForPause === "builtin" && free && !free.paused) free.pause();
    else if (activeForPause !== "builtin") {
      const pause = window.VeraSpotify?.pausePlayback;
      if (typeof pause === "function") await Promise.resolve(pause());
    } else {
      if (free && !free.paused) free.pause();
      const pause = window.VeraSpotify?.pausePlayback;
      if (typeof pause === "function") await Promise.resolve(pause());
    }
    if (free && activeForPause === "builtin") {
      freeMusicSyncNowFromAudio(prefix);
      spotifySyncPlayButtonUi(prefix);
    }
    musicSourceMarkPausedByUser();
    return { op, transportProvider: activeForPause };
  }
  if (op === "resume") {
    const activeForResume = resolveMusicTransportProvider(prefix, seqCtx);
    if (activeForResume === "builtin") {
      const free = document.getElementById(`${prefix}-free-music-audio`);
      if (free?.src) {
        await free.play().then(() => {
          freeMusicSyncNowFromAudio(prefix);
          spotifySyncPlayButtonUi(prefix);
        });
        return { op, transportProvider: "builtin" };
      }
    }
    const resume = window.VeraSpotify?.resumePlayback;
    if (typeof resume === "function") await Promise.resolve(resume());
    return { op, transportProvider: activeForResume };
  }
  if (op === "volume_delta") {
    if (!shouldApplyMusicTransportAction(payload, op)) return;
    const cur = typeof window.VeraSpotify?.getVolume === "function"
      ? window.VeraSpotify.getVolume()
      : spotifyGetVolume();
    const setVolume = window.VeraSpotify?.setVolume;
    const next = Math.max(0, Math.min(SPOTIFY_VOLUME_MAX, Number(cur) + (Number(payload.delta) || 0)));
    if (typeof setVolume === "function") await Promise.resolve(setVolume(next));
    else {
      window.__veraSpotifyVolume = next;
      const free = document.getElementById(`${prefix}-free-music-audio`);
      if (free) free.volume = next;
      const preview = document.getElementById(`${prefix}-spotify-preview-audio`);
      if (preview) preview.volume = next;
    }
    return { op, transportProvider: resolveMusicTransportProvider(prefix, seqCtx) };
  }
  const skipPanelRepeat = isRecentSameMusicPlay(payload, op);
  const sidePaneEl = uiEl("side-pane");
  if (sidePaneEl && !skipPanelRepeat) {
    const hasProductivityMarkup =
      Boolean(sidePaneEl.innerHTML.trim()) && sidePaneEl.dataset.sidePaneKind === "productivity";
    document.querySelectorAll(".productivity-mode-btn").forEach((b) => b.classList.remove("is-active"));
    if (hasProductivityMarkup) {
      if (sidePaneEl.hidden) restoreProductivityPanel(prefix);
    } else {
      renderProductivityPanel();
    }
    document.getElementById(`${prefix}-productivity-mode`)?.classList.add("is-active");
  }
  if (op === "play_builtin" && shouldPlayMusicThisInvocation(payload, op)) {
    await ensureSingleActiveMusicProvider("builtin", { reason: "play_builtin" });
    const sourceStateBeforeBuiltinPlay = veraMusicSourceState();
    const preservedBuiltinTime =
      sourceStateBeforeBuiltinPlay.builtin.state === "suspended_for_spotify"
        ? Number(sourceStateBeforeBuiltinPlay.builtin.currentTime || 0)
        : 0;
    musicSourceMarkPlaying("builtin", {
      playlistId: payload.playlist_id || "",
      soundId: payload.sound_id || "",
      currentTime: preservedBuiltinTime
    });
    const pfx = appModePrefix();
    console.info("[music_control_payload]", {
      music_play_op: "play_builtin",
      play_builtin_called: true,
      playback_backend: "builtin_audio",
      playlist_id: payload.playlist_id || "",
      sound_id: payload.sound_id || "",
      request_id: data?.request_id || null
    });
    try {
      await runBuiltinVoicePlayback(pfx, {
        playlistId: payload.playlist_id,
        soundId: payload.sound_id
      });
      if (preservedBuiltinTime > 0) {
        const free = document.getElementById(`${pfx}-free-music-audio`);
        if (free && Number.isFinite(free.duration) && preservedBuiltinTime < free.duration) {
          try {
            free.currentTime = preservedBuiltinTime;
            freeMusicSyncNowFromAudio(pfx);
          } catch (_) {
            /* keep playback going even if seeking fails */
          }
        }
      }
      console.info("[music_control_payload]", {
        music_play_op: "play_builtin",
        playback_started: true,
        playback_backend: "builtin_audio",
        request_id: data?.request_id || null
      });
    } catch (err) {
      console.warn("[music_control_payload]", {
        music_play_op: "play_builtin",
        playback_error: String(err && err.message || err || "unknown"),
        playback_backend: "builtin_audio",
        request_id: data?.request_id || null
      });
    }
    return { op, targetProvider: "builtin" };
  }
  if (op === "play_track" && payload.uri && shouldPlayMusicThisInvocation(payload, op)) {
    await ensureSingleActiveMusicProvider("spotify", { reason: "play_track" });
    musicSourceMarkPlaying("spotify", {
      uri: payload.uri,
      title: payload.title || "",
      artist: payload.artist || ""
    });
    const play = window.VeraSpotify?.playTrack;
    console.info("[music_control_payload]", {
      music_play_op: "play_track",
      playback_backend: "spotify",
      spotify_playtrack_available: typeof play === "function",
      title: payload.title || "",
      artist: payload.artist || "",
      requested_spotify_uri: String(payload.uri || ""),
      request_id: data?.request_id || null
    });
    if (typeof play === "function") {
      try {
        await Promise.resolve(play(String(payload.uri), {
          title: payload.title || "",
          artist: payload.artist || "",
          preview_url: payload.preview_url || "",
          open_url: payload.open_url || ""
        }));
        console.info("[music_control_payload]", {
          music_play_op: "play_track",
          playback_started: true,
          playback_backend: "spotify",
          request_id: data?.request_id || null
        });
      } catch (err) {
        console.warn("[music_control_payload]", {
          music_play_op: "play_track",
          playback_error: String(err && err.message || err || "unknown"),
          playback_backend: "spotify",
          request_id: data?.request_id || null
        });
      }
    }
    return { op, targetProvider: "spotify", expectedTrack: payload.title || "" };
  }
  if (op === "play_playlist_scoped" && shouldPlayMusicThisInvocation(payload, op)) {
    const rawQuery = String(payload.query || "").trim();
    const playlistId = String(payload.playlist_id || window.__veraSpotifyActivePlaylistId || "").trim();
    const playlistName = String(payload.playlist_name || window.__veraSpotifyActivePlaylistName || "").trim();
    console.info("[music_control_payload]", {
      music_play_op: "play_playlist_scoped",
      playback_backend: "spotify",
      playlist_scope_query: rawQuery,
      selected_playlist_id: playlistId,
      selected_playlist_name: playlistName,
      request_id: data?.request_id || null
    });
    const artistEl = document.getElementById(`${prefix}-spotify-track-artist`);
    if (!playlistId) {
      if (artistEl) artistEl.textContent = "Which playlist should I search?";
      return;
    }
    await ensureSingleActiveMusicProvider("spotify", { reason: "play_playlist_scoped" });
    const getTracks = window.VeraSpotify?.getPlaylistTracks;
    if (typeof getTracks !== "function") {
      if (artistEl) artistEl.textContent = "Playlist search is not available right now.";
      return;
    }
    let tracks = [];
    try {
      tracks = await getTracks(playlistId);
    } catch (err) {
      if (artistEl) artistEl.textContent = "Couldn't load that playlist's tracks.";
      console.warn("[music_control_payload]", {
        music_play_op: "play_playlist_scoped",
        playback_error: String(err && err.message || err || "unknown"),
        request_id: data?.request_id || null
      });
      return;
    }
    const needle = rawQuery.toLowerCase();
    const tokens = needle.split(/\s+/).filter((t) => t && t.length >= 3);
    let best = null;
    let bestScore = 0;
    for (const t of (tracks || [])) {
      const title = String(t.name || t.title || "").toLowerCase();
      const artistLine = (Array.isArray(t.artists)
        ? t.artists.map((a) => a?.name || "").join(", ")
        : String(t.artist || "")).toLowerCase();
      let score = 0;
      if (title === needle) score = 1.0;
      else if (title.includes(needle)) score = 0.9;
      else if (tokens.length && tokens.every((tok) => title.includes(tok))) score = 0.75;
      else if (artistLine.includes(needle)) score = 0.5;
      if (score > bestScore) {
        bestScore = score;
        best = t;
      }
    }
    const confident = best && bestScore >= 0.75;
    if (!confident) {
      if (artistEl) artistEl.textContent = `I couldn't find "${rawQuery}" in ${playlistName || "that playlist"}.`;
      return;
    }
    const uri = String(best.uri || "");
    if (!uri) {
      if (artistEl) artistEl.textContent = `Found "${best.name || best.title}" but couldn't play it.`;
      return;
    }
    const title = String(best.name || best.title || "");
    const artistStr = Array.isArray(best.artists)
      ? best.artists.map((a) => a?.name || "").filter(Boolean).join(", ")
      : String(best.artist || "");
    musicSourceMarkPlaying("spotify", {
      uri,
      title,
      artist: artistStr,
      playlist_id: playlistId,
      playlist_name: playlistName
    });
    const playFn = window.VeraSpotify?.playTrack;
    if (typeof playFn !== "function") {
      if (artistEl) artistEl.textContent = "Spotify playback is not available.";
      return;
    }
    try {
      await playFn(uri, { title, artist: artistStr });
      console.info("[music_control_payload]", {
        music_play_op: "play_playlist_scoped",
        playback_started: true,
        playback_backend: "spotify",
        requested_spotify_uri: uri,
        new_spotify_track: `${title} — ${artistStr}`,
        request_id: data?.request_id || null
      });
    } catch (err) {
      console.warn("[music_control_payload]", {
        music_play_op: "play_playlist_scoped",
        playback_error: String(err && err.message || err || "unknown"),
        request_id: data?.request_id || null
      });
    }
    return { op, targetProvider: "spotify", expectedTrack: rawQuery };
  }
  if (op === "play_album" && payload.uri && shouldPlayMusicThisInvocation(payload, op)) {
    await ensureSingleActiveMusicProvider("spotify", { reason: "play_album" });
    musicSourceMarkPlaying("spotify", {
      uri: payload.uri,
      title: payload.title || "",
      artist: payload.artist || ""
    });
    const playCtx = window.VeraSpotify?.playPlaylist;
    if (typeof playCtx === "function") {
      const base = localBackendBase();
      const uri = String(payload.uri || "").trim();
      const title = payload.title || "";
      const artist = payload.artist || "";
      const sub = artist ? `"${title}" by "${artist}"` : `"${title}"`;
      const openUrl = String(payload.open_url || spotifyUriToOpenUrl(uri) || "").trim();
      const st = await fetch(`${base}/api/spotify/connection-status`, {
        credentials: "include",
        headers: { ...veraSpotifyAuthHeaders() }
      })
        .then((r) => (r.ok ? r.json() : { connected: false }))
        .catch(() => ({ connected: false }));
      const artistEl = document.getElementById(`${prefix}-spotify-track-artist`);
      if (st.connected) {
        await playCtx(uri, { playlist_name: title, context_subtitle: sub });
      } else if (openUrl) {
        window.open(openUrl, "_blank", "noopener,noreferrer");
        if (artistEl) {
          artistEl.textContent =
            `${artist ? `${artist} — ` : ""}Opened Spotify in a new tab (connect for in-page playback).`.trim();
        }
      } else if (artistEl) {
        artistEl.textContent = "Connect Spotify to play this album in VERA.";
      }
    }
    return { op, targetProvider: "spotify", expectedTrack: payload.title || "" };
  }
  if (op === "play_playlist_by_name") {
    const rawName = String(payload.playlist_name || "").trim();
    if (!rawName || !shouldPlayMusicThisInvocation(payload, op)) return;
    const built = matchBuiltinPlaylistOrSoundNameForClient(rawName);
    if (built) {
      await ensureSingleActiveMusicProvider("builtin", { reason: "play_playlist_by_name_builtin" });
      musicSourceMarkPlaying("builtin", {
        playlistId: built.playlistId || "",
        soundId: built.soundId || ""
      });
      await runBuiltinVoicePlayback(prefix, built);
      return { op, targetProvider: "builtin", expectedTrack: rawName };
    }
    const getLists = window.VeraSpotify?.getPlaylists;
    const playCtx = window.VeraSpotify?.playPlaylist;
    const artistEl = document.getElementById(`${prefix}-spotify-track-artist`);
    if (typeof getLists !== "function" || typeof playCtx !== "function") {
      if (artistEl) artistEl.textContent = "Playlist playback is not available.";
      return;
    }
    const lists = await getLists().catch(() => []);
    const needle = rawName.toLowerCase();
    let hit =
      lists.find((p) => String(p.name || "").toLowerCase() === needle) ||
      lists.find((p) => String(p.name || "").toLowerCase().includes(needle));
    if (!hit && needle.length >= 3) {
      hit = lists.find((p) => needle.includes(String(p.name || "").toLowerCase()));
    }
    if (!hit?.uri) {
      if (artistEl) artistEl.textContent = `No playlist in your library matched "${rawName}".`;
      return;
    }
    const disp = hit.name || rawName;
    await ensureSingleActiveMusicProvider("spotify", { reason: "play_playlist_by_name_spotify" });
    musicSourceMarkPlaying("spotify", {
      uri: hit.uri,
      playlist_id: String(hit.id || hit.uri || ""),
      playlist_name: disp
    });
    await playCtx(hit.uri, {
      playlist_name: disp,
      context_subtitle: `"${disp}" in my playlist`
    });
    return { op, targetProvider: "spotify", expectedTrack: disp };
  }
}

function _usageTrackActionExecuted(payload, data, seqCtx, extra) {
  try {
    if (payload?.panel_type === "checklist_control") {
      const hasIdx =
        Number.isFinite(Number(seqCtx?.orderIndex)) ||
        Number.isFinite(Number(payload?.planner_action_index));
      if (!hasIdx) return;
    }
    window.veraUsageOnActionExecuted?.(
      payload,
      {
        requestId: data?.request_id,
        actionPlanId: payload?.action_plan_id || data?.action_plan_id,
        orderIndex: seqCtx?.orderIndex,
        source: seqCtx?.source || data?.type || "unknown",
      },
      extra
    );
  } catch (_) {}
}

function _usageSkipFinalizeActionApply(payload) {
  const panelType = payload?.panel_type || "";
  if (panelType === "checklist_control") return true;
  return false;
}

async function applyActionPayload(data, seqCtx = {}) {
  // 2026-05-29 — multi-action planner pass-through.
  // When the backend executed a typed compound command, every action's
  // ui_payload arrives in data.action_payloads in execution order. We
  // apply each one through this same function (recursive single-payload
  // dispatch) so every existing per-panel branch below keeps working
  // unchanged. We deliberately also apply data.action_payload at the end
  // when it's the FIRST payload (it duplicates data.action_payloads[0]
  // when both are present — skip in that case to avoid double-render).
  const planned = Array.isArray(data?.action_payloads) ? data.action_payloads.filter(Boolean) : [];
  if (planned.length > 1) {
    if (typeof window.veraApplyActionPayloadsInOrder === "function") {
      await window.veraApplyActionPayloadsInOrder(
        planned,
        (payload, ctx) =>
          applyActionPayload({ ...data, action_payload: payload, action_payloads: null }, ctx),
        { requestId: data?.request_id || null, source: seqCtx?.source || "multi_action_payloads" }
      );
      return;
    }
    const seen = new WeakSet();
    for (let idx = 0; idx < planned.length; idx++) {
      const p = planned[idx];
      if (!p || typeof p !== "object") continue;
      if (seen.has(p)) continue;
      seen.add(p);
      try {
        await applyActionPayload({ ...data, action_payload: p, action_payloads: null }, { orderIndex: idx });
      } catch (err) {
        console.warn("[planner] action_payloads dispatch failed", { idx, err });
      }
    }
    return;
  }
  const payload = data?.action_payload;
  const lockToMusicPanel =
    isVeraWorkModeOn() && appModePrefix() === "vera";

  if (
    lockToMusicPanel &&
    (payload?.panel_type === "media_tabs" ||
      payload?.panel_type === "news_results" ||
      payload?.panel_type === "finance_chart" ||
      payload?.panel_type === "product_results_panel" ||
      payload?.panel_type === "location_map_panel")
  ) {
    const sidePaneEl = uiEl("side-pane");
    if (sidePaneEl) {
      const hasProductivityMarkup =
        Boolean(sidePaneEl.innerHTML.trim()) && sidePaneEl.dataset.sidePaneKind === "productivity";
      if (hasProductivityMarkup) {
        if (sidePaneEl.hidden) restoreProductivityPanel("vera");
      } else {
        renderProductivityPanel();
      }
    }
    return;
  }

  if (payload?.panel_type === "media_tabs" || payload?.panel_type === "news_results") {
    /* Large innerHTML (news + images + video embeds) can block the main thread; defer so BMO mouth RAF keeps up. */
    requestAnimationFrame(() => renderMediaTabsPanel(payload));
    _usageTrackActionExecuted(payload, data, seqCtx);
    return;
  }

  /* News panel UI command — pure open/close, never a Work Mode reasoning
     panel switch. Backend emits this when the user says "open the news
     panel", "show news tab", "close news". The render path reuses the
     existing News Results panel surface (or hides it). Empty headlines
     are fine — the user asked for a UI surface, not a briefing. */
  if (payload?.panel_type === "news_panel_ui") {
    const op = (payload.op || "open").toLowerCase();
    if (op === "close") {
      hideSidePanel();
      console.info("[news_panel_ui]", { stage: "frontend", op: "close" });
      _usageTrackActionExecuted(payload, data, seqCtx);
      return;
    }
    /* op === "open" — render the news panel shell. If we have no fresh
       results, show an empty headlines placeholder so the panel surface
       exists and the user can use the tab controls. We deliberately do
       NOT trigger a Serper call here — the user only asked for the UI. */
    const openPayload = {
      panel_type: "news_results",
      title: payload.title || "News",
      query: payload.query || "Latest headlines",
      default_tab: "news",
      news_results: [],
      results: [],
      images: [],
      videos: [],
    };
    requestAnimationFrame(() => renderMediaTabsPanel(openPayload));
    console.info("[news_panel_ui]", { stage: "frontend", op: "open" });
    _usageTrackActionExecuted(payload, data, seqCtx);
    return;
  }

  if (payload?.panel_type === "finance_chart") {
    renderFinanceChartPanel(payload);
    return;
  }

  if (payload?.panel_type === "product_results_panel") {
    requestAnimationFrame(() => renderProductResultsPanel(payload));
    return;
  }

  if (payload?.panel_type === "location_map_panel") {
    requestAnimationFrame(() => renderLocationMapPanel(payload));
    return;
  }

  if (payload?.panel_type === "checklist_control") {
    try {
      markWorkChecklistLocalMutation();
      if (Array.isArray(payload.items)) {
        localStorage.setItem(WORK_CHECKLIST_STORAGE_KEY, JSON.stringify(payload.items));
      }
      if (typeof payload.completed_collapsed === "boolean") {
        localStorage.setItem(
          WORK_CHECKLIST_COMPLETED_COLLAPSED_KEY,
          payload.completed_collapsed ? "1" : "0"
        );
      }
      loadWorkChecklistItems();
      syncWorkChecklistHelpPlanButton();
      try {
        const n = Array.isArray(payload.items) ? payload.items.length : 0;
        window.veraUsageOnChecklistMutation?.({
          op: "sync",
          item_count: n,
          batch_size: n || undefined,
          source: "voice",
          sync_kind: "plan",
          client_key: String(data?.request_id || ""),
        });
        _usageTrackActionExecuted(payload, data, seqCtx);
      } catch (_) {}
    } catch (_) {}
    return;
  }

  if (payload?.panel_type === "work_mode_reasoning") {
    if (!shouldApplyWorkModeReasoningInvocation(payload)) return;
    if (!isVeraWorkModeOn() || appModePrefix() !== "vera") return;
    const op = payload.op || "";
    if (op === "open_new") {
      const count = Math.max(1, Math.min(REASONING_TABS_MAX, Number(payload.count) || 1));
      const panelOpenRequestId = String(payload.panel_open_request_id || payload.new_panel_request_id || "").trim();
      const actionPlanId = String(payload.action_plan_id || "").trim();
      let activeBeforeOpen = null;
      try {
        const beforeOrder = typeof getReasoningPanelOrder === "function" ? getReasoningPanelOrder() : [];
        activeBeforeOpen = beforeOrder.find((p) => p?.isActive)?.laneId || null;
        console.info("[panel_action_start]", {
          op: "open_new",
          count,
          active_panel_before: activeBeforeOpen,
          panel_open_request_id: panelOpenRequestId || null,
          action_plan_id: actionPlanId || null,
          source: "frontend_open_new_applier",
        });
      } catch (_) {}
      if (panelOpenRequestId) {
        if (!window.__veraPanelOpenRequestIds || !(window.__veraPanelOpenRequestIds instanceof Map)) {
          window.__veraPanelOpenRequestIds = new Map();
        }
        const prev = window.__veraPanelOpenRequestIds.get(panelOpenRequestId);
        if (prev && performance.now() - Number(prev.at || 0) < 30000) {
          try {
            console.warn("[duplicate_panel_open_blocked]", {
              panel_open_request_id: panelOpenRequestId,
              previous_lane_id: prev.laneId || null,
              previous_tab_index: prev.tabIndex ?? null,
              action_plan_id: actionPlanId || null,
              source: "frontend_open_new_guard",
            });
          } catch (_) {}
          return;
        }
      }
      /* PART 5+6 (2026-05-28): tag each open with the backend-payload
         source so the recently-opened flag is set with provenance the
         dest-resolver log can show. */
      for (let i = 0; i < count; i += 1) {
        const opened = addReasoningTab({
          source: "backend_open_panel_action",
          requestId: panelOpenRequestId,
        });
        if (panelOpenRequestId && opened) {
          try {
            window.__veraPanelOpenRequestIds.set(panelOpenRequestId, {
              at: performance.now(),
              laneId: opened.laneId || "",
              tabIndex: opened.tabIndex,
            });
          } catch (_) {}
        }
        try {
          console.info("[panel_action_result]", {
            op: "open_new",
            opened_panel_id: opened?.laneId || null,
            opened_tab_index: opened?.tabIndex ?? null,
            active_panel_before: activeBeforeOpen,
            active_panel_after: opened?.laneId || null,
            panel_open_request_id: panelOpenRequestId || null,
            action_plan_id: actionPlanId || null,
            source: "frontend_open_new_applier",
          });
        } catch (_) {}
      }
      _usageTrackActionExecuted(payload, data, seqCtx);
      return;
    }
    /* PART 3: backend can also drive panel close (e.g. the LLM router sent
       back work_mode.reasoning_close_panel because the heuristic didn't
       fire, or via /infer for a typed command). The payload carries the
       parsed command shape from PART 14 and we re-run the executor here
       so the source of truth for index resolution + refill + active
       reselection stays in one place. */
    if (op === "close" || op === "close_panel" || op === "close_panels") {
      const userTextForClose = String(payload.user_text || "");
      /* PART 2: if the client-side shortcut already executed a close for
         this user turn, the backend round-trip is a stale echo. Skip the
         duplicate mutation; the bubble is already on screen. */
      if (_hasActiveReasoningCloseLock()) {
        logReasoningCloseConfirmationUiDebug({
          stage: "backend_payload_dedup_skip",
          close_panel_intent_detected: true,
          close_action_completed: true,
          confirmation_text: String(_peekReasoningCloseLock()?.confirmation || ""),
          confirmation_render_path: "assistant_bubble",
          confirmation_tts_enqueued: false,
          duplicate_confirmation_suppressed: true,
          action_result_consumed_by_normal_reply_pipeline: true,
          source: payload.reason || "backend_action_payload",
        });
        logReasoningClosePolishDebug({
          stage: "backend_payload_dedup_skip",
          reason: "client_lock_active",
          prev_lock: _peekReasoningCloseLock(),
          backend_op: op,
          backend_user_text: userTextForClose.slice(0, 200),
        });
        return;
      }
      const parsedRaw = payload.parsed && typeof payload.parsed === "object"
        ? payload.parsed
        : parseCloseReasoningPanelsCommand(userTextForClose, getReasoningPanelOrder().length);
      /* Backend "parsed" shape is the minimal subset; rerun the parser on
         the user text so we get the full scan/rank metadata and avoid
         losing the close-span deduplication logic. */
      const parsedFull = (parsedRaw && parsedRaw.allCloseSpans)
        ? parsedRaw
        : parseCloseReasoningPanelsCommand(userTextForClose, getReasoningPanelOrder().length);
      /* Use backend-provided slot if it carries info the user text doesn't
         expose (e.g. by_title where title came from LLM extraction). */
      const parsed = {
        ...parsedFull,
        ...(parsedRaw && parsedRaw.titleQuery ? { titleQuery: parsedRaw.titleQuery } : {}),
        ...(parsedRaw && (parsedRaw.closeScope === "by_title" || parsedRaw.closeScope === "reopen_last")
          ? { closeScope: parsedRaw.closeScope, parsedRangeType: parsedRaw.closeScope }
          : {}),
      };
      const exec = executeCloseReasoningPanelsCommand(parsed, {
        userText: userTextForClose,
        reason: payload.reason || "backend_action_payload",
      });
      /* PART 2: emit exactly one bubble — exec.confirmation when ok, or
         the failure reply otherwise. Backend's spoken_reply is NOT bubbled
         separately by us; the chat pipeline that delivered this payload
         is responsible for that. We set the lock so no further shortcuts
         in the same turn double-fire. */
      const reply = exec?.confirmation || buildCloseReasoningPanelsVoiceReply(exec, parsed);
      _setReasoningCloseLock({
        scope: parsed.closeScope,
        indices: parsed.indices || null,
        confirmation: reply,
        source: payload.reason || "backend_action_payload",
      });
      if (!exec.ok) {
        renderReasoningCloseAssistantConfirmation(reply, {
          path: "close-reasoning-panel-backend-failure",
          source: payload.reason || "backend_action_payload",
          isVoice: false,
          stage: "backend_payload_close_failure",
          closeActionCompleted: false,
        });
      } else {
        logReasoningCloseConfirmationUiDebug({
          stage: "backend_payload_close_success",
          close_panel_intent_detected: true,
          close_action_completed: true,
          confirmation_text: reply,
          confirmation_render_path: "assistant_bubble",
          confirmation_tts_enqueued: Boolean(
            !inputMuted &&
            !(appModePrefix() === "vera" && isVeraWorkModeOn() && isWorkModeMuteEnabled())
          ),
          duplicate_confirmation_suppressed: false,
          action_result_consumed_by_normal_reply_pipeline: true,
          source: payload.reason || "backend_action_payload",
        });
      }
      _usageTrackActionExecuted(payload, data, seqCtx, { success: Boolean(exec?.ok) });
      return;
    }
    if (op === "reopen_last") {
      if (_hasActiveReasoningCloseLock()) {
        logReasoningCloseConfirmationUiDebug({
          stage: "backend_payload_dedup_skip_reopen",
          close_panel_intent_detected: true,
          close_action_completed: true,
          confirmation_text: String(_peekReasoningCloseLock()?.confirmation || ""),
          confirmation_render_path: "assistant_bubble",
          confirmation_tts_enqueued: false,
          duplicate_confirmation_suppressed: true,
          action_result_consumed_by_normal_reply_pipeline: true,
          source: payload.reason || "backend_action_payload",
        });
        logReasoningClosePolishDebug({
          stage: "backend_payload_dedup_skip",
          reason: "client_lock_active",
          prev_lock: _peekReasoningCloseLock(),
          backend_op: op,
        });
        return;
      }
      const r = reopenLastClosedReasoningPanel({ userText: String(payload.user_text || "") });
      if (r.ok) {
        _setReasoningCloseLock({ scope: "reopen_last", indices: null, confirmation: "Bringing back the last closed panel.", source: payload.reason || "backend_action_payload" });
      }
      if (!r.ok && r.failureReason === "stack_empty") {
        renderReasoningCloseAssistantConfirmation("I don't have a recently closed panel to reopen.", {
          path: "reopen-reasoning-panel-empty-backend",
          source: payload.reason || "backend_action_payload",
          isVoice: false,
          stage: "backend_payload_reopen_empty",
          closeActionCompleted: false,
        });
      }
      return;
    }
    if (op === "activate" && payload.panel_index != null) {
      const idx = Number(payload.panel_index);
      if (!Number.isFinite(idx)) return;
      const guardText = inferUserTextForLaneActivationGuard(data);
      if (shouldBlockOrdinalProblemLaneActivation(guardText)) {
        console.info("[blocked_lane_activation]", {
          user_text: guardText,
          requested_panel_index: idx,
          reason: "ordinal_problem_not_tab_navigation"
        });
        return;
      }
      const panelEl = document.querySelector(
        `#vera-reasoning-tab-panels .vera-reasoning-tab-panel[data-tab-index="${idx}"]`
      );
      if (panelEl) {
        activateReasoningTab(idx, {
          commandText: guardText,
          requestedIndex: idx + 1,
          resolvedFrom: "visible_order",
        });
        _usageTrackActionExecuted(payload, data, seqCtx);
      }
      return;
    }
    if (op === "open_and_stream") {
      try {
        console.info("[reasoning_action_received]", {
          op,
          prompt_preview: String(payload?.prompt || "").slice(0, 160),
          target_panel_index_1based: payload?.target_panel_index_1based ?? null,
          active_lane_id: getActiveDomReasoningLaneId?.() || null,
          source: seqCtx?.source || data?.type || "unknown",
        });
        console.info("[reasoning_action_execute_start]", {
          op,
          active_lane_id: getActiveDomReasoningLaneId?.() || null,
        });
      } catch (_) {}
      /* 2026-05-29 spec PART 3 — open + stream a CLEAN reasoning prompt
         into a target panel. Driven by the backend planner's
         reasoning.request direct dispatcher; the prompt arrives
         already-stripped of music/panel/timer/checklist phrases. We
         reuse the existing Work Mode reasoning lane machinery rather
         than open a brand-new surface. */
      applyWorkModeReasoningOpenAndStreamPayload(payload, data);
      try {
        console.info("[reasoning_action_execute_done]", {
          op,
          active_lane_id: getActiveDomReasoningLaneId?.() || null,
        });
      } catch (_) {}
      _usageTrackActionExecuted(payload, data, seqCtx);
      return;
    }
    return;
  }

  if (payload?.panel_type === "music_control") {
    const musicResult = await applyMusicControlPayloadAsync(payload, data, seqCtx);
    if (musicResult && typeof musicResult === "object" && musicResult.op) {
      try {
        window.veraUsageOnMusicControlApplied?.(
          payload,
          {
            requestId: data?.request_id,
            actionPlanId: payload?.action_plan_id || data?.action_plan_id,
            orderIndex: seqCtx?.orderIndex,
            source: seqCtx?.source || data?.type || "unknown",
          },
          musicResult
        );
      } catch (_) {}
    }
    return musicResult;
  }

  /* Keep the music panel open across normal assistant replies unless a new panel payload replaces it. */
  const sidePaneEl = uiEl("side-pane");
  if (
    sidePaneEl &&
    !sidePaneEl.hidden &&
    sidePaneEl.dataset.sidePaneKind === "productivity"
  ) {
    return;
  }

  hideSidePanel();
}

/** News/finance side panel + assistant bubble — call when main reply audio actually starts (not when LLM JSON/meta arrives). */
function applyAssistantReplyAndPanels(data) {
  if (!data) return;
  if (data.work_mode_timer) {
    applyWorkModeTimerPayload(data.work_mode_timer);
  }
  applyActionPayload(data);
  if (data.reply == null || data.reply === "") return;
  // Real reply is taking over — drop the "Searching news…" placeholder
  // before the actual assistant bubble appears so the user only sees the
  // final answer (no double-bubble flash).
  cancelPendingNewsStatusBubble("assistant_reply_applied");
  const bubble = addBubble(data.reply, "vera");
  veraFeedbackMarkFinalFromBubble(bubble, data, null);
}

function createNdjsonStreamingReplyState(initialReplyBack = null, opts = {}) {
  return {
    bubble: null,
    latest: "",
    pendingVoiceQuote: replyBackQuoteText(initialReplyBack),
    pendingReplyBack: initialReplyBack,
    /** When true, ignore streamed reply_so_far until finalize sets the canonical line. */
    suppressReplyProgress: Boolean(opts.suppressReplyProgress),
    stage2EffectiveLocked: false
  };
}

/**
 * Grow one assistant bubble as each NDJSON chunk includes reply_so_far (sentence-cumulative text).
 */
function applyNdjsonStreamingReplySoFar(replySoFar, state) {
  if (replySoFar == null || replySoFar === "") return;
  if (state?.suppressReplyProgress || state?.stage2EffectiveLocked) return;
  state.latest = String(replySoFar);
  const convoEl = uiEl("conversation");
  if (!convoEl) return;
  const text = state.latest;
  if (state.bubble?.isConnected) {
    const cur = state.bubble.textContent || "";
    /* Done line can arrive before deferred first play; finalize may have filled the full reply — don't overwrite with a shorter cumulative partial. */
    if (text.length >= cur.length) {
      state.bubble.textContent = text;
    }
  } else {
    // Streaming reply is about to create the real bubble — drop the
    // "Searching news…" placeholder so they don't sit side-by-side.
    cancelPendingNewsStatusBubble("ndjson_reply_so_far");
    let opts = { path: "ndjson-reply-so-far" };
    if (state.pendingReplyBack) {
      opts = mergeReplyBackIntoBubbleMeta(opts, state.pendingReplyBack);
      state.pendingReplyBack = null;
      state.pendingVoiceQuote = null;
    }
    state.bubble = addBubble(text, "vera", opts);
  }
  convoEl.scrollTop = convoEl.scrollHeight;
  persistVeraChatState();
}

/** After NDJSON done: sync bubble to final reply, or add bubble if no streaming partials. */
function finalizeNdjsonStreamingReply(ndjsonMeta, done, state) {
  if (!done?.reply) return;
  const merged = {
    ...(ndjsonMeta && typeof ndjsonMeta === "object" ? ndjsonMeta : {}),
    ...done,
    reply: done.reply
  };
  if (
    !state.pendingReplyBack &&
    merged.work_mode_voice_brief_completion === true &&
    merged.work_mode_voice_quote != null &&
    String(merged.work_mode_voice_quote).trim()
  ) {
    const q = String(merged.work_mode_voice_quote).trim();
    if (q) {
      state.pendingVoiceQuote = q;
      state.pendingReplyBack = {
        reply_to_user_text: q,
        reply_to_turn_id: "",
        reply_to_lane_id: "",
        reply_to_lane_title: "",
        stage: 2
      };
    }
  }
  const pay = merged?.action_payload;
  const op = pay?.op;
  if (
    pay?.panel_type === "music_control" &&
    (op === "skip_next" || op === "skip_previous" || op === "play_builtin")
  ) {
    applyActionPayload(merged);
  }
  /* Work Mode Stage 2: one bubble with reply-back is created via ensureStage2VoiceBubble after resolve. */
  if (state?.suppressReplyProgress) {
    state.latest = String(done.reply || "");
    state.stage2EffectiveLocked = true;
    persistVeraChatState();
    return;
  }
  if (state.bubble?.isConnected) {
    state.bubble.textContent = done.reply;
    state.stage2EffectiveLocked = true;
    veraFeedbackMarkFinalFromBubble(state.bubble, merged, null);
    persistVeraChatState();
    return;
  }
  /* Must assign state.bubble so applyNdjsonStreamingReplySoFar doesn't add a second bubble if done arrives before first audio (defer path). */
  if (!_usageSkipFinalizeActionApply(pay)) {
    applyActionPayload(merged);
  }
  // Streaming finalized without ever calling onReplyProgress (no partials),
  // so we drop the pending bubble here just before creating the final one.
  cancelPendingNewsStatusBubble("ndjson_finalize");
  let finOpts = { path: "ndjson-final" };
  if (state.pendingReplyBack) {
    finOpts = mergeReplyBackIntoBubbleMeta(finOpts, state.pendingReplyBack);
    state.pendingReplyBack = null;
    state.pendingVoiceQuote = null;
  }
  state.bubble = addBubble(done.reply, "vera", finOpts);
  state.stage2EffectiveLocked = true;
  veraFeedbackMarkFinalFromBubble(state.bubble, merged, null);
  persistVeraChatState();
}

/** Stops TTS and resets interrupt UI counters (shared by heuristic + browser barge-in). */
function cancelBrowserInterruptTtsOnly() {
  const a = getAudioEl();
  const audioPausedBefore = a ? Boolean(a.paused) : null;
  const audioEndedBefore = a ? Boolean(a.ended) : null;
  logInterruptChain("tts_stop_attempt", {
    hasAudioEl: Boolean(a),
    audioPausedBefore,
    audioEndedBefore,
    mainTtsPlaybackActive,
    activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
  });

  /* PART 1 — record entry into the shared cancel path. */
  _recordInterruptTimingPoint("t5_interruptSpeech_entered", {
    extra: { gatePath: "cancelBrowserInterruptTtsOnly" },
  });
  /* PART 1/3 — t8: UI flipped from speaking → interrupted. */
  _recordInterruptTimingPoint("t8_ui_state_set_interrupted");
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    "interrupted",
    "interrupt_browser_or_single_asr",
    "cancelBrowserInterruptTtsOnly"
  );
  setStatus("Listening… (interrupted)", "recording");
  resetAudioHandlers();
  cancelMainTtsPlayback();
  if (a) {
    a.pause();
    a.currentTime = 0;
  }
  logInterruptChain("tts_stop_done", {
    audioPausedAfter: a ? Boolean(a.paused) : null,
    audioEndedAfter: a ? Boolean(a.ended) : null,
    mainTtsPlaybackActive,
    activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
  });
  /* PART 1 — t11: audio element paused after cancel. */
  _recordInterruptTimingPoint("t11_audio_audibly_stopped", {
    extra: { path: "cancelBrowserInterruptTtsOnly" },
  });
  /* PART 1/3 — t9: voice state flipped to listening. */
  _logVoiceStateTransition(
    "interrupted",
    "listening",
    "cancelBrowserInterruptTtsOnly_complete",
    "cancelBrowserInterruptTtsOnly"
  );
  listening = true;
  processing = false;
  waveState = "listening";
  _recordInterruptTimingPoint("t9_ui_state_set_listening");
  interruptSpeechFrames = 0;
  interruptSpeechStart = 0;
  interruptSpeechAccumMs = 0;
  lastInterruptDetectTime = 0;
  interruptLastSpeechLikeTime = 0;
  lastInterruptSpeechLikeSnapshot = null;
  interruptLastVoiceTime = performance.now();
  /* PART 1 — flush trace on next tick to capture any tail t10/t11 events. */
  try {
    setTimeout(
      () => _flushInterruptDelayTrace("cancelBrowserInterruptTtsOnly_complete"),
      0
    );
  } catch (_) {}
}

function promoteInterruptPreviewToMainLiveBubble() {
  if (interruptDetectionBubbleEl?.isConnected) {
    mainBrowserLiveBubble = interruptDetectionBubbleEl;
    interruptDetectionBubbleEl = null;
    try {
      mainBrowserLiveBubble.classList.remove("interrupt-preview");
    } catch (_) {}
  }
}

/**
 * Browser ASR: >2 words ⇒ stop TTS; keep the same SpeechRecognition session and use 1.3s stable transcript → LLM.
 * (Does not start a second recognition — that was the old post-interrupt listener.)
 */
function onBrowserInterruptBargeInFromDetect(event) {
  if (interruptBargeInLatched) return;
  interruptBargeInLatched = true;
  const commitAt = performance.now();
  vadFastStopAsrFinalAt = commitAt;
  /* PART 1 — t5: barge-in handler entered. */
  _recordInterruptTimingPoint("t5_interruptSpeech_entered", {
    extra: { gatePath: "onBrowserInterruptBargeInFromDetect" },
  });
  // Latency telemetry: if the fast VAD stop already fired earlier in
  // this TTS turn, report the gap between the two events so we can see
  // exactly how much speak-over time was saved. If the heuristic never
  // fired (rare on desktop, common in PTT), the ASR path was the only
  // gate; both metrics become null/0 in that case.
  const vadFiredEarlier = vadFastStopFiredAt > 0;
  logBargeInLatencyDebug("final_asr_received", {
    tts_playing: isAssistantTtsPlaying(),
    tts_id: vadFastStopTtsId || interruptPrearmTtsId || null,
    delay_vad_to_tts_stop_ms: vadFiredEarlier
      ? Number((vadFastStopTtsStoppedAt - vadFastStopFiredAt).toFixed(2))
      : null,
    delay_vad_to_final_asr_ms: vadFiredEarlier
      ? Number((vadFastStopAsrFinalAt - vadFastStopFiredAt).toFixed(2))
      : null,
    audio_already_stopped_by_vad: vadFiredEarlier,
    note: vadFiredEarlier
      ? "TTS stopped on VAD; final ASR transcript routes intent"
      : "no early VAD trigger; ASR alone drove this barge-in"
  });
  cancelBrowserInterruptTtsOnly();
  promoteInterruptPreviewToMainLiveBubble();
  mainBrowserFinalizeKind = "interrupt";

  let interimBuf = "";
  let finalP = "";
  let _sawFinal = false;
  for (let i = 0; i < event.results.length; i++) {
    const r = event.results[i];
    if (r.isFinal) {
      const piece = r[0].transcript;
      finalP += piece;
      _sawFinal = true;
      logPartialAsrSegmentFinal(piece.trim(), { mode: "interrupt-barge" });
    } else {
      interimBuf += r[0].transcript;
    }
  }
  /* PART 1 — t3: first final fragment from the browser SR (if any).
     Useful to verify TTS cancel did NOT wait for this point. */
  if (_sawFinal) {
    _recordInterruptTimingPoint("t3_final_transcript_available", {
      extra: { finalLen: finalP.length },
    });
  }
  mainBrowserFinalTranscript = finalP;
  mainBrowserLastInterim = interimBuf;
  const _wasSpokenInterruptOnResult = hasSpoken;
  hasSpoken =
    mainBrowserFinalTranscript.trim().length > 0 || interimBuf.trim().length > 0;
  if (hasSpoken && !_wasSpokenInterruptOnResult) {
    armVoiceMaxDurationTimer("browser_asr_first_partial_interrupt");
  }
  if (hasSpoken && speechWaitTimeoutId != null) {
    clearTimeout(speechWaitTimeoutId);
    speechWaitTimeoutId = null;
  }
  updateMainBrowserLiveBubble(mainBrowserFinalTranscript, interimBuf);
  logInterruptTranscriptDebug("capture_committed", {
    included_preroll_ms: 0,
    live_capture_started_at_ms: Number((interruptPartialLastChangeAt || commitAt).toFixed(1)),
    bubble_created_at_ms: Number(commitAt.toFixed(1)),
    asr_request_started_at_ms: null,
    browser_asr_live_stream: true
  });
  scheduleMainBrowserEndOfUtterance();
}

/* interruptSpeech → moved to voice/interruption.js (Stage 6, 2026-05-27). */

function detectInterrupt() {
  if (!analyser) {
    requestAnimationFrame(detectInterrupt);
    return;
  }

  /*
   * Previously: when the browser-ASR detector was alive on desktop, the
   * heuristic RAF loop returned early — meaning TTS only stopped AFTER
   * Chrome's Web Speech API produced enough words. That added 300-700ms
   * of "VERA talking over me" latency.
   *
   * New behaviour: the heuristic loop ALWAYS runs while TTS is playing.
   * In browser-ASR mode we still defer the full barge-in transition
   * (bubble promotion, transcript routing) to the SR session — but we
   * use VAD as a fast audio-only kill switch via fastStopTtsOnVadOnly().
   * That keeps intent classification on the SR transcript (per spec)
   * while removing the user-perceived speak-over latency.
   */
  const browserAsrParallelMode =
    browserAsrPreferred() && !isNarrowViewport() && !!interruptDetectRecognition;

  const buf = new Float32Array(analyser.fftSize);
  analyser.getFloatTimeDomainData(buf);

  // RMS
  let sum = 0;
  for (let i = 0; i < buf.length; i++) sum += buf[i] * buf[i];
  const rms = Math.sqrt(sum / buf.length);

  // ZCR (voicing) + crest (reject single sharp transients from bumps/clicks)
  const zcr = computeZCR(buf);
  let peak = 0;
  for (let i = 0; i < buf.length; i++) {
    const a = Math.abs(buf[i]);
    if (a > peak) peak = a;
  }
  const crest = peak / (rms + 1e-8);

  const now = performance.now();

  // Only interrupt while main TTS is playing: single-file uses <audio>; chunked/streaming uses Web Audio BufferSources.
  const outAudio = getAudioEl();
  const htmlAudioPlaying = outAudio && !outAudio.paused;
  const webAudioMainTtsPlaying =
    activeMainTtsBufferSources.length > 0 || mainTtsPlaybackActive;

  /* DEBUG: RAF gap measurement. If the main thread stalls (e.g. news
     panel render), detectInterrupt RAF frames are dropped and VAD
     accumulates wall-clock without contributing to interrupt detection.
     We log any gap > 100ms while TTS is playing. */
  if (isVeraInterruptDebugEnabled()) {
    try {
      if (_veraInterruptRafLastAt > 0) {
        const gapMs = now - _veraInterruptRafLastAt;
        if (gapMs > 100 && (htmlAudioPlaying || webAudioMainTtsPlaying)) {
          logVeraInterruptDebug({
            tag: "interrupt_raf_gap",
            now: Number(now.toFixed(1)),
            gapMs: Number(gapMs.toFixed(1)),
            duringNewsRender: _veraNewsPanelRenderInFlight,
            ttsPlaying: Boolean(htmlAudioPlaying || webAudioMainTtsPlaying)
          });
        }
      }
      _veraInterruptRafLastAt = now;
    } catch (_) {}
  }

  if (
  listeningMode === "continuous" &&
  (htmlAudioPlaying || webAudioMainTtsPlaying)
) {
    // grace period to avoid clicks
    if (now - audioStartedAt > 200) {
      const dtRaw = lastInterruptDetectTime ? now - lastInterruptDetectTime : 0;
      const dt = Math.min(Math.max(dtRaw, 0), 80);
      lastInterruptDetectTime = now;

      const heuristicChecks = computeHeuristicInterruptChecks(rms, zcr, crest);
      const rawSpeechLike = heuristicChecks.passes;
      const whisperVadPath =
        whisperInterruptCaptureNeeded() && !browserAsrParallelMode;
      const speechWindowMsBefore =
        interruptSpeechStart > 0 ? now - interruptSpeechStart : 0;
      const frameClass = whisperVadPath
        ? classifyWhisperInterruptFrame(rms, zcr, crest, speechWindowMsBefore)
        : { valid: rawSpeechLike, rejectedReason: null };
      const validInterruptSpeechFrame = frameClass.valid;
      const rejectedReason = frameClass.rejectedReason;
      const effectiveSpeechLike = whisperVadPath
        ? validInterruptSpeechFrame
        : rawSpeechLike;
      if (whisperVadPath) {
        if (
          isWhisperHarshOnsetSignal(
            rms,
            zcr,
            crest,
            speechWindowMsBefore,
            rejectedReason
          )
        ) {
          whisperInterruptSpikyOrRaspyStart = true;
        }
        if (whisperInterruptSpikyOrRaspyStart) {
          if (
            isWhisperSmoothContinuationFrame(
              rms,
              zcr,
              crest,
              validInterruptSpeechFrame
            )
          ) {
            whisperInterruptSmoothFrames++;
          } else {
            whisperInterruptSmoothFrames = 0;
          }
        }
      }
      const gapResetMs = whisperVadPath
        ? WHISPER_INTERRUPT_GAP_RESET_MS
        : INTERRUPT_GAP_RESET_MS;
      const sustainMs = whisperVadPath
        ? getWhisperInterruptSustainMs()
        : getInterruptSustainMs();
      const cooldownActive = whisperVadPath && now < whisperInterruptCooldownUntil;
      const smoothFramesRequired = WHISPER_SMOOTH_FRAMES_AFTER_RASPY_START;
      const smoothGateAllowsTrigger =
        !whisperVadPath ||
        !whisperInterruptSpikyOrRaspyStart ||
        whisperInterruptSmoothFrames >= smoothFramesRequired;
      const smoothContinuationReady = smoothGateAllowsTrigger;
      const strongFrame =
        whisperVadPath &&
        isWhisperStrongInterruptFrame(rms, zcr, crest, speechWindowMsBefore);

      if (whisperVadPath ? validInterruptSpeechFrame : effectiveSpeechLike) {
        if (whisperInterruptValidFrames === 0 && interruptSpeechFrames === 0) {
          interruptSpeechStart = now;
          _recordInterruptTimingPoint("t0_user_speech_audio_detected", {
            autoStart: true,
            extra: {
              rms: Number(rms.toFixed(5)),
              zcr: Number(zcr.toFixed(4)),
              crest: Number(crest.toFixed(2)),
              browserAsrParallelMode,
              timeSinceTtsStartMs: Number((now - (audioStartedAt || now)).toFixed(1)),
            },
          });
        }
        if (whisperVadPath) {
          whisperInterruptValidFrames++;
          if (
            whisperInterruptValidFrames >= WHISPER_MIN_VALID_FRAMES_BEFORE_SUSTAIN &&
            smoothGateAllowsTrigger
          ) {
            interruptSpeechAccumMs += dt;
            interruptSpeechFrames++;
            interruptLastSpeechLikeTime = now;
            lastInterruptSpeechLikeSnapshot = {
              rms,
              zcr,
              crest,
              heuristicChecks,
              at: now,
            };
            if (strongFrame) {
              whisperInterruptStrongFrames++;
            } else {
              whisperInterruptStrongFrames = 0;
            }
          }
        } else {
          interruptSpeechAccumMs += dt;
          if (interruptSpeechFrames === 0) {
            interruptSpeechStart = now;
          }
          interruptSpeechFrames++;
          interruptLastSpeechLikeTime = now;
          lastInterruptSpeechLikeSnapshot = {
            rms,
            zcr,
            crest,
            heuristicChecks,
            at: now,
          };
        }
      } else if (
        interruptLastSpeechLikeTime &&
        now - interruptLastSpeechLikeTime <= gapResetMs
      ) {
        // Allow tiny gaps so normal speech doesn't need a perfect uninterrupted stream.
      } else {
        interruptSpeechFrames = 0;
        interruptSpeechStart = 0;
        interruptSpeechAccumMs = 0;
        interruptLastSpeechLikeTime = 0;
        lastInterruptSpeechLikeSnapshot = null;
        resetWhisperInterruptCandidateState();
      }

      const speechWindowMs = interruptSpeechStart ? now - interruptSpeechStart : 0;
      const requiredStrongFrames = whisperVadPath ? getWhisperStrongFramesRequired() : 0;
      const sustainArmed =
        !whisperVadPath ||
        whisperInterruptValidFrames >= WHISPER_MIN_VALID_FRAMES_BEFORE_SUSTAIN;
      const sustainReadyRaw =
        sustainArmed &&
        validInterruptSpeechFrame &&
        interruptSpeechFrames >= INTERRUPT_MIN_FRAMES &&
        interruptSpeechAccumMs >= sustainMs;
      const strongCountOk =
        whisperVadPath && whisperInterruptStrongFrames >= requiredStrongFrames;
      const strongWindowOk = speechWindowMs >= WHISPER_STRONG_MIN_WINDOW_MS;
      const spikyShortBurst =
        whisperVadPath &&
        !validInterruptSpeechFrame &&
        (rejectedReason === "spiky_short_burst" ||
          (crest > WHISPER_SPIKY_CREST_REJECT &&
            speechWindowMs < WHISPER_SPIKY_BURST_WINDOW_MS));
      const strongReadyRaw =
        WHISPER_STRONG_INTERRUPT_PATH_ENABLED &&
        whisperVadPath &&
        strongCountOk &&
        strongWindowOk &&
        validInterruptSpeechFrame &&
        !spikyShortBurst;
      const sustainReady = sustainReadyRaw && smoothGateAllowsTrigger;
      const strongReady = strongReadyRaw && smoothGateAllowsTrigger;
      const triggerReady = !cooldownActive && (sustainReady || strongReady);
      const triggerGate = strongReady
        ? "whisper_strong_frames"
        : sustainReady
          ? "whisper_sustain"
          : strongReadyRaw && !smoothGateAllowsTrigger
            ? "strong_ready_blocked_by_smooth_gate"
            : sustainReadyRaw && !smoothGateAllowsTrigger
              ? "sustain_ready_blocked_by_smooth_gate"
              : null;

      if (whisperVadPath) {
        const reasonIfNotTriggering = whisperVadReasonIfNotTriggering({
          rawSpeechLike,
          validInterruptSpeechFrame,
          rejectedReason:
            !validInterruptSpeechFrame && (rawSpeechLike || rejectedReason)
              ? rejectedReason
              : null,
          validFrameCount: whisperInterruptValidFrames,
          consecutiveSpeechFrames: interruptSpeechFrames,
          requiredSpeechFrames: INTERRUPT_MIN_FRAMES,
          accumMs: interruptSpeechAccumMs,
          sustainMs,
          strongFrames: whisperInterruptStrongFrames,
          requiredStrongFrames,
          speechWindowMs,
          requiredStrongWindowMs: WHISPER_STRONG_MIN_WINDOW_MS,
          cooldownActive,
          interruptRecording,
          sustainReady,
          strongReady,
          sustainReadyRaw,
          strongReadyRaw,
          smoothGateAllowsTrigger,
          spikyShortBurst,
          crest,
          spikyOrRaspyStart: whisperInterruptSpikyOrRaspyStart,
          smoothFrameCount: whisperInterruptSmoothFrames,
          smoothFramesRequired,
          smoothContinuationReady,
        });
        logInterruptChain(
          "vad_trigger_eval",
          {
            rms: Number(rms.toFixed(5)),
            zcr: Number(zcr.toFixed(4)),
            crest: Number(crest.toFixed(2)),
            rawSpeechLike,
            validInterruptSpeechFrame,
            effectiveSpeechLike,
            rejectedReason,
            validFrameCount: whisperInterruptValidFrames,
            strongFrameCount: whisperInterruptStrongFrames,
            interruptSpeechAccumMs: Number(interruptSpeechAccumMs.toFixed(1)),
            sustainTargetMs: sustainMs,
            spikyOrRaspyStart: whisperInterruptSpikyOrRaspyStart,
            smoothFrameCount: whisperInterruptSmoothFrames,
            smoothFramesRequired,
            smoothContinuationReady,
            smoothGateAllowsTrigger,
            sustainReadyRaw,
            strongReadyRaw,
            sustainReady,
            strongReady,
            triggerReady,
            triggerGate,
            interruptRecording,
            ttsPlaying: true,
            asrMode: (function () {
              try {
                return getVeraAsrMode();
              } catch (_) {
                return null;
              }
            })(),
            consecutiveSpeechFrames: interruptSpeechFrames,
            requiredSpeechFrames: INTERRUPT_MIN_FRAMES,
            requiredStrongFrames,
            speechWindowMs: Number(speechWindowMs.toFixed(1)),
            requiredStrongWindowMs: WHISPER_STRONG_MIN_WINDOW_MS,
            spikyShortBurst,
            sustainArmed,
            interruptCooldownActive: cooldownActive,
            inputMuted,
            listeningMode,
            sustainReady,
            strongReady,
            reasonIfNotTriggering,
          },
          {
            throttleKey:
              rawSpeechLike || validInterruptSpeechFrame
                ? "vad_trigger_eval_speech"
                : "vad_trigger_eval",
            throttleMs: rawSpeechLike || validInterruptSpeechFrame ? 120 : 400,
          }
        );
        if (
          (rawSpeechLike || validInterruptSpeechFrame) &&
          !triggerReady &&
          reasonIfNotTriggering
        ) {
          logInterruptChain(
            "vad_speechlike_no_interrupt",
            {
              reason: reasonIfNotTriggering,
              rawSpeechLike,
              validInterruptSpeechFrame,
              rejectedReason,
              validFrameCount: whisperInterruptValidFrames,
              consecutiveSpeechFrames: interruptSpeechFrames,
              strongFrameCount: whisperInterruptStrongFrames,
              requiredStrongFrames,
              speechWindowMs: Number(speechWindowMs.toFixed(1)),
              requiredStrongWindowMs: WHISPER_STRONG_MIN_WINDOW_MS,
              interruptSpeechAccumMs: Number(interruptSpeechAccumMs.toFixed(1)),
              sustainTargetMs: sustainMs,
              interruptRecording,
              ttsPlaying: true,
              asrMode: (function () {
                try {
                  return getVeraAsrMode();
                } catch (_) {
                  return null;
                }
              })(),
            },
            { throttleKey: "vad_speechlike_no_interrupt", throttleMs: 150 }
          );
        }
        logInterruptChain(
          "vad_during_tts",
          {
            rms: Number(rms.toFixed(5)),
            zcr: Number(zcr.toFixed(4)),
            crest: Number(crest.toFixed(2)),
            rawSpeechLike,
            validInterruptSpeechFrame,
            effectiveSpeechLike,
            rejectedReason,
            strongFrame,
            ttsPlaying: true,
            interruptRecording,
            validFrameCount: whisperInterruptValidFrames,
            strongFrameCount: whisperInterruptStrongFrames,
            interruptSpeechAccumMs: Number(interruptSpeechAccumMs.toFixed(1)),
            sustainTargetMs: sustainMs,
            asrMode: (function () {
              try {
                return getVeraAsrMode();
              } catch (_) {
                return null;
              }
            })(),
          },
          { throttleKey: "vad_during_tts_whisper", throttleMs: 250 }
        );
      }

      logVeraInterruptDebug(
        {
          tag: "interrupt_vad_frame",
          now: Number(now.toFixed(1)),
          listeningMode,
          asrMode: (function () { try { return getVeraAsrMode(); } catch (_) { return null; } })(),
          browserAsrPreferred: (function () { try { return browserAsrPreferred(); } catch (_) { return null; } })(),
          browserAsrParallelMode,
          assistantTtsPlaying: (function () { try { return isAssistantTtsPlaying(); } catch (_) { return null; } })(),
          mainTtsPlaybackActive,
          activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
          htmlAudioPlaying: Boolean(htmlAudioPlaying),
          rms: Number(rms.toFixed(5)),
          zcr: Number(zcr.toFixed(4)),
          crest: Number(crest.toFixed(2)),
          speechLike: rawSpeechLike,
          validInterruptSpeechFrame: whisperVadPath ? validInterruptSpeechFrame : undefined,
          vadAccumMs: Number(interruptSpeechAccumMs.toFixed(1)),
          sustainThresholdMs: sustainMs,
          vadThresholdPassed: triggerReady,
          interruptRecording,
          vadFastStopArmed,
          activeNdjsonBodyReaderPresent: Boolean(activeNdjsonBodyReader),
          audioStartedAt: Number(Number(audioStartedAt || 0).toFixed(1)),
          timeSinceTtsStartMs: Number((now - (audioStartedAt || now)).toFixed(1)),
          duringNewsRender: _veraNewsPanelRenderInFlight
        },
        { throttleKey: "interrupt_vad_frame", throttleMs: 250 }
      );

      if (triggerReady) {
        const gate = strongReady
          ? "whisper_strong_frames"
          : whisperVadPath
            ? "whisper_sustain"
            : "heuristic";
        const triggerKind =
          gate === "whisper_strong_frames"
            ? `whisper_strong_frames (${whisperInterruptStrongFrames} strong frames, window ≥ ${WHISPER_STRONG_MIN_WINDOW_MS}ms)`
            : gate === "whisper_sustain"
              ? `whisper_sustain (accumulated valid speech ≥ ${sustainMs}ms)`
              : `heuristic (accumulated speechLike time ≥ ${sustainMs}ms)`;
        const snap = lastInterruptSpeechLikeSnapshot;
        const triggerSpeechLike = whisperVadPath ? validInterruptSpeechFrame : rawSpeechLike;
        logInterruptTriggerReason({
          gate,
          triggerKind,
          triggerFrame: { rms, zcr, crest, speechLike: triggerSpeechLike },
          lastSpeechLike: snap,
          speechAccumMs: interruptSpeechAccumMs,
          wallMsSinceFirstSpeech: interruptSpeechStart
            ? now - interruptSpeechStart
            : 0,
          rafFrames: interruptSpeechFrames,
        });
        lastInterruptProbe = {
          atTrigger: { rms, zcr, crest, speechLike: triggerSpeechLike },
          lastSpeechLike: snap,
          interruptGate: gate,
          interruptReason: gate,
          heuristicChecks: snap?.heuristicChecks ?? heuristicChecks,
          speechAccumMs: interruptSpeechAccumMs,
          wallMsSinceFirstSpeech: interruptSpeechStart
            ? now - interruptSpeechStart
            : 0,
          frames: interruptSpeechFrames,
        };
        logInterruptTranscriptDebug("speech_detected", {
          tts_id: interruptPrearmTtsId || null,
          time_since_tts_start_ms: Number((now - (audioStartedAt || now)).toFixed(1)),
          speech_confirm_delay_ms: Number((interruptSpeechAccumMs || 0).toFixed(1)),
          rms: Number(rms.toFixed(5)),
          vad_score: Number((triggerSpeechLike ? 1 : 0).toFixed(2)),
          preroll_available_ms: interruptPrearmStartedAt
            ? Number(Math.min(MAX_INTERRUPTION_PREROLL_MS, now - interruptPrearmStartedAt).toFixed(1))
            : 0,
          gate: browserAsrParallelMode ? "heuristic_fast_stop" : gate
        });

        /* DEBUG: VAD threshold passed — log before dispatch so we know
           which branch will fire and what the state looks like. */
        logVeraInterruptDebug({
          tag: "interrupt_vad_threshold_passed",
          now: Number(now.toFixed(1)),
          gate: browserAsrParallelMode ? "browser_asr_parallel" : "single_asr_interrupt_speech",
          rms: Number(rms.toFixed(5)),
          zcr: Number(zcr.toFixed(4)),
          crest: Number(crest.toFixed(2)),
          vadAccumMs: Number(interruptSpeechAccumMs.toFixed(1)),
          rafFrames: interruptSpeechFrames,
          interruptRecording,
          mainTtsPlaybackActive,
          activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
          activeNdjsonBodyReaderPresent: Boolean(activeNdjsonBodyReader),
          timeSinceTtsStartMs: Number((now - (audioStartedAt || now)).toFixed(1)),
          duringNewsRender: _veraNewsPanelRenderInFlight
        });

        if (browserAsrParallelMode) {
          // Parallel mode: VAD only cancels audio. The browser-ASR
          // session keeps running and will deliver the final transcript
          // (see onBrowserInterruptBargeInFromDetect for the bubble +
          // routing). Reset the heuristic counters so we don't fire the
          // fast-stop more than once per TTS turn.
          /* PART 1 — t4: gate passed, intent confirmed (VAD parallel). */
          _recordInterruptTimingPoint("t4_interrupt_intent_detected", {
            autoStart: true,
            extra: { gate: "heuristic_fast_stop" },
          });
          fastStopTtsOnVadOnly({
            rms,
            zcr,
            crest,
            vadAccumMs: interruptSpeechAccumMs
          });
        } else {
          /* PART 1 — t4: gate passed, intent confirmed (single-ASR heuristic). */
          _recordInterruptTimingPoint("t4_interrupt_intent_detected", {
            autoStart: true,
            extra: { gate: "heuristic_single_asr", whisperStrong: strongReady },
          });
          logInterruptChain("vad_calling_interrupt_speech", {
            consecutiveSpeechFrames: interruptSpeechFrames,
            strongFrames: whisperInterruptStrongFrames,
            rms: Number(rms.toFixed(5)),
            zcr: Number(zcr.toFixed(4)),
            asrMode: (function () {
              try {
                return getVeraAsrMode();
              } catch (_) {
                return null;
              }
            })(),
            gate,
          });
          whisperInterruptCooldownUntil = now + WHISPER_INTERRUPT_COOLDOWN_MS;
          interruptSpeech();
        }
        interruptSpeechFrames = 0;
        interruptSpeechStart = 0;
        interruptSpeechAccumMs = 0;
        interruptLastSpeechLikeTime = 0;
        lastInterruptSpeechLikeSnapshot = null;
        resetWhisperInterruptCandidateState();
      }

      if (
        MOBILE_VAD_DEBUG &&
        now - lastMobileVadSampleLogAt >= MOBILE_VAD_SAMPLE_INTERVAL_MS
      ) {
        lastMobileVadSampleLogAt = now;
        pushMobileInterruptVadLog(
          `vad rms=${rms.toFixed(4)} zcr=${zcr.toFixed(4)} crest=${crest.toFixed(2)} like=${speechLike} acc=${interruptSpeechAccumMs.toFixed(0)}ms thr=${getInterruptSustainMs()}ms`
        );
      }
    }
  } else {
    interruptSpeechFrames = 0;
    interruptSpeechStart = 0;
    interruptSpeechAccumMs = 0;
    lastInterruptDetectTime = 0;
    interruptLastSpeechLikeTime = 0;
    lastInterruptSpeechLikeSnapshot = null;
    resetWhisperInterruptCandidateState();
  }

  requestAnimationFrame(detectInterrupt);
}

function resetAudioHandlers() {
  const a = getAudioEl();
  if (a) {
    a.onplay = null;
    a.onended = null;
  }
}

let interruptLastVoiceTime = 0;

function detectInterruptSpeechEnd() {
  if (!interruptRecording || interruptRecorder?.state !== "recording") return;

  const buf = new Float32Array(analyser.fftSize);
  analyser.getFloatTimeDomainData(buf);

  let sum = 0;
  for (let i = 0; i < buf.length; i++) sum += buf[i] * buf[i];
  const rms = Math.sqrt(sum / buf.length);

  const now = performance.now();

  if (listeningFrameIsSpeechLike(buf, rms)) {
    interruptLastVoiceTime = now;
  }

  if (
    interruptLastVoiceTime &&
    now - interruptLastVoiceTime > SILENCE_MS
  ) {
    interruptRecorder.stop(); // ✅ NOW stop
    interruptRecording = false;
    return;
  }

  requestAnimationFrame(detectInterruptSpeechEnd);
}

function computeZCR(buf) {
  let crossings = 0;
  for (let i = 1; i < buf.length; i++) {
    if ((buf[i - 1] >= 0 && buf[i] < 0) ||
        (buf[i - 1] < 0 && buf[i] >= 0)) {
      crossings++;
    }
  }
  return crossings / buf.length;
}

/* listeningFrameIsSpeechLike (RMS + ZCR voiced-band gate) -> moved to
 * voice/asr.js (Stage 22 / Patch A-11, 2026-05-31). voice/asr.js loads
 * before app.js per index.html, so the function is reachable as a bare
 * identifier from both the main VAD loop (detectSpeech, also moved) and
 * the interrupt VAD loop (detectInterruptSpeechEnd at L18024, NOT
 * moved) through the shared classic-script global lexical environment
 * at call time. Thresholds (VOLUME_THRESHOLD, LISTEN_END_ZCR_MIN/MAX,
 * IS_MOBILE) remain declared in app.js and are read cross-file. */

/** Per-threshold flags for interrupt (RMS/ZCR/crest); all must pass for a frame to count as speech-like. */
function computeHeuristicInterruptChecks(rms, zcr, crest) {
  const rmsAboveMin = rms > INTERRUPT_RMS;
  const rmsBelowMax = rms < MAX_SPEECH_RMS;
  const zcrInRange = zcr >= INTERRUPT_ZCR_MIN && zcr <= INTERRUPT_ZCR_MAX;
  const crestOk = crest <= INTERRUPT_MAX_CREST;
  return {
    rmsAboveMin,
    rmsBelowMax,
    zcrInRange,
    crestOk,
    passes:
      rmsAboveMin && rmsBelowMax && zcrInRange && crestOk,
  };
}

function logWhisperInterruptQa(stage, detail, fields = {}) {
  try {
    console.warn(detail ? `[${stage}] ${detail}` : `[${stage}]`, {
      timestamp: new Date().toISOString(),
      ...fields,
    });
  } catch (_) {}
  try {
    window.veraUsageOnInterruptQa?.(stage, detail, fields);
  } catch (_) {}
}

function getWhisperInterruptConfirmationState() {
  let asrMode = null;
  let whisperCaptureNeeded = false;
  let browserParallel = false;
  let confirmationEnabled = false;
  try {
    asrMode = getVeraAsrMode();
    whisperCaptureNeeded = whisperInterruptCaptureNeeded();
    browserParallel =
      browserAsrPreferred() && !isNarrowViewport() && !!interruptDetectRecognition;
    confirmationEnabled = whisperCaptureNeeded && !browserParallel;
  } catch (_) {}
  return {
    asrMode,
    whisperCaptureNeeded,
    browserParallel,
    confirmationEnabled,
  };
}

function logInterruptTriggerReason({
  gate,
  triggerKind,
  triggerFrame,
  lastSpeechLike,
  speechAccumMs,
  wallMsSinceFirstSpeech,
  rafFrames,
}) {
  const base = {
    gate,
    speechAccumMs: Number(speechAccumMs.toFixed(1)),
    wallMsSinceFirstSpeech: Number(wallMsSinceFirstSpeech.toFixed(1)),
    rafFrames,
    triggerKind:
      triggerKind ||
      `speech_frame (accumulated speechLike time ≥ ${getInterruptSustainMs()}ms)`,
    triggerFrame: {
      rms: Number(triggerFrame.rms.toFixed(5)),
      zcr: Number(triggerFrame.zcr.toFixed(5)),
      crest: Number(triggerFrame.crest.toFixed(4)),
      speechLike: triggerFrame.speechLike,
    },
  };
  const h =
    lastSpeechLike?.heuristicChecks ??
    computeHeuristicInterruptChecks(
      lastSpeechLike?.rms ?? triggerFrame.rms,
      lastSpeechLike?.zcr ?? triggerFrame.zcr,
      lastSpeechLike?.crest ?? triggerFrame.crest
    );
  const checks = [];
  if (h.rmsAboveMin) checks.push("rms_min");
  if (h.rmsBelowMax) checks.push("rms_max");
  if (h.zcrInRange) checks.push("zcr");
  if (h.crestOk) checks.push("crest");
  const isWhisperCandidateGate =
    gate === "whisper_sustain" || gate === "whisper_strong_frames";
  logWhisperInterruptQa("INTERRUPT_CANDIDATE", gate, {
    ...base,
    note: isWhisperCandidateGate
      ? "VAD candidate only — awaiting Whisper transcript confirmation"
      : "VAD candidate",
    lastSpeechLike: lastSpeechLike
      ? {
          rms: Number(lastSpeechLike.rms.toFixed(5)),
          zcr: Number(lastSpeechLike.zcr.toFixed(5)),
          crest: Number(lastSpeechLike.crest.toFixed(4)),
          heuristicChecks: checks.join("+"),
        }
      : null,
  });
  pushMobileInterruptVadLog(
    `[INTERRUPT_CANDIDATE] ${gate} accumMs=${speechAccumMs.toFixed(1)} rms=${triggerFrame.rms.toFixed(5)} zcr=${triggerFrame.zcr.toFixed(5)} crest=${triggerFrame.crest.toFixed(4)} checks=${checks.join("+")}`
  );
}

function pushMobileInterruptVadLog(msg) {
  if (!MOBILE_VAD_DEBUG) return;
  const t = new Date().toISOString().slice(11, 23);
  interruptVadLogLines.push(`[${t}] ${msg}`);
  if (interruptVadLogLines.length > INTERRUPT_VAD_LOG_MAX) {
    interruptVadLogLines.splice(0, interruptVadLogLines.length - INTERRUPT_VAD_LOG_MAX);
  }
  renderMobileInterruptVadLogs();
}

function renderMobileInterruptVadLogs() {
  const text = interruptVadLogLines.join("\n");
  const p1 = document.getElementById("vera-interrupt-debug-pre");
  const p2 = document.getElementById("bmo-interrupt-debug-pre");
  if (p1) p1.textContent = text;
  if (p2) p2.textContent = text;
}

function toggleInterruptDebugPanel(prefix) {
  const panel = document.getElementById(`${prefix}-interrupt-debug-panel`);
  const btn = document.getElementById(`${prefix}-interrupt-debug-toggle`);
  const headerBtn = document.getElementById(`${prefix}-interrupt-debug-header`);
  if (!panel) return;
  const opening = panel.hidden;
  panel.hidden = !opening;
  const expanded = opening ? "true" : "false";
  btn?.setAttribute("aria-expanded", expanded);
  headerBtn?.setAttribute("aria-expanded", expanded);
  if (opening) {
    requestAnimationFrame(() => {
      panel.scrollIntoView({ block: "end", behavior: "smooth" });
    });
  }
}

function injectMobileVadLogUiIfNeeded() {
  if (!MOBILE_VAD_DEBUG) return;
  document.body.classList.add("vad-log-mode");

  const veraHeader = document.querySelector("#vera-app .vera-app-header");
  const veraOpenBmo = document.getElementById("open-bmo-from-vera");
  if (veraHeader && veraOpenBmo && !document.getElementById("vera-interrupt-debug-header")) {
    const wrap = document.createElement("div");
    wrap.className = "vera-header-actions";
    const vadBtn = document.createElement("button");
    vadBtn.type = "button";
    vadBtn.id = "vera-interrupt-debug-header";
    vadBtn.className = "interrupt-debug-header-btn";
    vadBtn.setAttribute("aria-controls", "vera-interrupt-debug-panel");
    vadBtn.textContent = "VAD log";
    veraOpenBmo.parentNode.insertBefore(wrap, veraOpenBmo);
    wrap.appendChild(vadBtn);
    wrap.appendChild(veraOpenBmo);
  }

  const bmoHeader = document.querySelector("#bmo-page .bmo-chat-header");
  if (bmoHeader && !document.getElementById("bmo-interrupt-debug-header")) {
    const vadBtn = document.createElement("button");
    vadBtn.type = "button";
    vadBtn.id = "bmo-interrupt-debug-header";
    vadBtn.className = "interrupt-debug-header-btn";
    vadBtn.setAttribute("aria-controls", "bmo-interrupt-debug-panel");
    vadBtn.textContent = "VAD log";
    bmoHeader.appendChild(vadBtn);
  }

  function buildExtender(prefix) {
    const wrap = document.createElement("div");
    wrap.className = "interrupt-debug-extender";
    const toggle = document.createElement("button");
    toggle.type = "button";
    toggle.id = `${prefix}-interrupt-debug-toggle`;
    toggle.className = "interrupt-debug-toggle";
    toggle.setAttribute("aria-expanded", "false");
    toggle.setAttribute("aria-controls", `${prefix}-interrupt-debug-panel`);
    toggle.textContent = "Interrupt / VAD log";
    const panel = document.createElement("div");
    panel.id = `${prefix}-interrupt-debug-panel`;
    panel.className = "interrupt-debug-panel";
    panel.hidden = true;
    const pre = document.createElement("pre");
    pre.id = `${prefix}-interrupt-debug-pre`;
    pre.className = "interrupt-debug-pre";
    pre.setAttribute("aria-live", "polite");
    const clearBtn = document.createElement("button");
    clearBtn.type = "button";
    clearBtn.id = `${prefix}-interrupt-debug-clear`;
    clearBtn.className = "interrupt-debug-clear";
    clearBtn.textContent = "Clear";
    panel.appendChild(pre);
    panel.appendChild(clearBtn);
    wrap.appendChild(toggle);
    wrap.appendChild(panel);
    return wrap;
  }

  const veraIc = document.querySelector("#vera-app .input-container");
  if (veraIc && !document.getElementById("vera-interrupt-debug-panel")) {
    veraIc.appendChild(buildExtender("vera"));
  }

  const bmoIc = document.querySelector("#bmo-page .input-container");
  if (bmoIc && !document.getElementById("bmo-interrupt-debug-panel")) {
    bmoIc.appendChild(buildExtender("bmo"));
  }
}

function wireMobileInterruptDebugUi() {
  if (!MOBILE_VAD_DEBUG) return;
  injectMobileVadLogUiIfNeeded();
  pushMobileInterruptVadLog(
    `sustain=${getInterruptSustainMs()}ms (${INTERRUPT_SUSTAIN_MS_PHONE}ms phone / ${INTERRUPT_SUSTAIN_MS_DESKTOP}ms desktop viewport)`
  );
  ["vera", "bmo"].forEach((prefix) => {
    const btn = document.getElementById(`${prefix}-interrupt-debug-toggle`);
    const headerBtn = document.getElementById(`${prefix}-interrupt-debug-header`);
    const panel = document.getElementById(`${prefix}-interrupt-debug-panel`);
    const clearBtn = document.getElementById(`${prefix}-interrupt-debug-clear`);
    if (!panel) return;
    const toggle = () => toggleInterruptDebugPanel(prefix);
    btn?.addEventListener("click", toggle);
    headerBtn?.addEventListener("click", toggle);
    clearBtn?.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      interruptVadLogLines.length = 0;
      renderMobileInterruptVadLogs();
    });
  });
}

function getInterruptMicTrackStates() {
  try {
    return (micStream?.getAudioTracks?.() || []).map((t) => ({
      readyState: t.readyState,
      enabled: t.enabled,
      muted: t.muted,
    }));
  } catch (_) {
    return [];
  }
}

function isMicStreamLiveForInterrupt() {
  if (!micStream) return false;
  try {
    const tracks = micStream.getAudioTracks?.() || [];
    if (!tracks.length) return Boolean(micStream.active);
    return tracks.some((t) => t.readyState === "live");
  } catch (_) {
    return false;
  }
}

async function ensureMicStreamForInterrupt() {
  if (isMicStreamLiveForInterrupt()) {
    if (!inputMuted) {
      try {
        micStream.getAudioTracks?.().forEach((t) => {
          if (t.readyState === "live") t.enabled = true;
        });
      } catch (_) {}
    }
    return true;
  }
  if (micStream) {
    try {
      micStream.getTracks().forEach((t) => t.stop());
    } catch (_) {}
    micStream = null;
  }
  try {
    await initMic();
  } catch (_) {
    return false;
  }
  return isMicStreamLiveForInterrupt();
}

function whisperInterruptCaptureNeeded() {
  try {
    if (isWhisperAsrMode()) return true;
    if (isHybridAsrMode() && !browserAsrPreferred()) return true;
  } catch (_) {}
  return false;
}

async function armInterruptCaptureAtTtsStart({ ttsId = "" } = {}) {
  const asrMode = (function () {
    try {
      return getVeraAsrMode();
    } catch (_) {
      return null;
    }
  })();

  logInterruptChain("tts_start", {
    asrMode,
    listeningMode,
    continuousListen: listeningMode === "continuous",
    ttsPlaying: (function () {
      try {
        return isAssistantTtsPlaying();
      } catch (_) {
        return null;
      }
    })(),
    micStreamExists: Boolean(micStream),
    micStreamActive: Boolean(micStream?.active),
    micStreamLive: isMicStreamLiveForInterrupt(),
    interruptRecording,
    hasInterruptRecorder: Boolean(interruptRecorder),
  });

  if (whisperInterruptCaptureNeeded() && listeningMode === "continuous" && !inputMuted) {
    const micOk = await ensureMicStreamForInterrupt();
    if (!micOk) {
      logInterruptChain("start_capture_skipped", {
        reason: "mic_stream_unavailable_after_reacquire",
        asrMode,
      });
    }
  }

  logInterruptChain("start_capture_called", { asrMode });
  resetWhisperInterruptVadTriggerState();
  startInterruptCapture();
  void prearmInterruptCaptureForTts({ ttsId });
}

function startInterruptCapture() {
  /* DEBUG: log every call to startInterruptCapture and every early exit
     so we can confirm interruptRecording is flipped true for single-ASR
     news responses. The "stays false for whole response" hypothesis
     hinges on this firing. */
  const _dbgState = (event, extra) => logVeraInterruptDebug({
    tag: "interrupt_capture_state",
    event,
    now: Number(performance.now().toFixed(1)),
    listeningMode,
    inputMuted,
    useBrowserAsr: (function () { try { return browserAsrPreferred(); } catch (_) { return null; } })(),
    isNarrowViewport: (function () { try { return isNarrowViewport(); } catch (_) { return null; } })(),
    interruptRecording,
    interruptRecorderState: interruptRecorder?.state ?? null,
    interruptChunksCount: Array.isArray(interruptChunks) ? interruptChunks.length : null,
    prearmActive: Boolean(interruptPrearmRecorder && interruptPrearmRecorder.state === "recording"),
    ttsPlaying: (function () { try { return isAssistantTtsPlaying(); } catch (_) { return null; } })(),
    currentTtsId: interruptPrearmTtsId || null,
    actionType: _veraCurrentTtsDebugContext?.actionType ?? null,
    ...(extra || {})
  });

  const asrMode = (function () {
    try {
      return getVeraAsrMode();
    } catch (_) {
      return null;
    }
  })();

  logInterruptChain("start_capture_state", {
    asrMode,
    micStreamExists: Boolean(micStream),
    micStreamActive: Boolean(micStream?.active),
    micStreamLive: isMicStreamLiveForInterrupt(),
    trackStates: getInterruptMicTrackStates(),
    interruptRecording,
    hasInterruptRecorder: Boolean(interruptRecorder),
    recorderState: interruptRecorder?.state ?? null,
  });

  _dbgState("start_called");

  if (listeningMode !== "continuous") {
    interruptRecording = false;
    interruptChunks = [];
    logInterruptChain("start_capture_skipped", { reason: "not_continuous", asrMode });
    _dbgState("start_aborted", { reason: "not_continuous" });
    return;
  }
  if (inputMuted) {
    interruptRecording = false;
    interruptChunks = [];
    stopAllBrowserSpeechRecognizers();
    showMutedStatusIfIdle();
    logInterruptChain("start_capture_skipped", { reason: "input_muted", asrMode });
    _dbgState("start_aborted", { reason: "input_muted" });
    return;
  }
  if (browserAsrPreferred() && !isNarrowViewport()) {
    startInterruptBrowserPartialDetection();
    logInterruptChain("start_capture_skipped", {
      reason: "browser_asr_partial_detection_used",
      asrMode,
    });
    _dbgState("start_aborted", { reason: "browser_asr_partial_detection_used" });
    return;
  }

  // 🔥 HARD FLUSH — stop and discard any previous capture
  if (interruptRecorder && interruptRecorder.state !== "inactive") {
    try {
      interruptRecorder.ondataavailable = null;
      interruptRecorder.onstop = null;
      interruptRecorder.stop();
    } catch {}
  }

  interruptRecorder = null;
  interruptRecording = false;
  interruptChunks = [];
  interruptSpeechFrames = 0;
  interruptSpeechStart = 0;
  interruptSpeechAccumMs = 0;
  lastInterruptDetectTime = 0;
  interruptLastSpeechLikeTime = 0;
  lastInterruptSpeechLikeSnapshot = null;
  interruptPrearmStartedAt = performance.now();

  // ---------- START / COMMIT RECORDER ----------
  // If TTS pre-armed a rolling recorder, keep the same recorder alive so
  // the eventual ASR upload contains the user's first words. The old path
  // created MediaRecorder only after VAD confirmed speech, which could miss
  // the phrase opening ("wait actually", "pause", "stop").
  if (
    interruptPrearmRecorder &&
    interruptPrearmRecorder.state === "recording"
  ) {
    try {
      interruptPrearmRecorder.requestData?.();
    } catch (_) {}
    interruptRecorder = interruptPrearmRecorder;
    interruptChunks = interruptPrearmChunks.map((x) => x?.blob).filter(Boolean);
    interruptPrearmCommittedAt = performance.now();
    interruptPrearmRecorder = null;
    interruptPrearmChunks = [];
    interruptRecorder.ondataavailable = (e) => {
      if (e.data && e.data.size > 0) {
        interruptChunks.push(e.data);
      }
    };
    interruptRecorder.onstop = () => {
      _dbgState("recorder_stopped", { path: "prearm_commit" });
      const chunksCount = interruptChunks.length;
      const blob = new Blob(interruptChunks, { type: "audio/webm" });
      logInterruptChain("interrupt_audio_finalized", {
        blobSize: blob.size,
        chunksCount,
        durationMsApprox: interruptPrearmStartedAt
          ? Number(Math.max(0, performance.now() - interruptPrearmStartedAt).toFixed(1))
          : null,
        willSendToWhisper: blob.size >= MIN_AUDIO_BYTES && whisperInterruptCaptureNeeded(),
        path: "prearm_commit",
      });
      interruptRecorder = null;
      interruptRecording = false;
      interruptChunks = [];
      handleInterruptUtterance(blob);
    };
    interruptRecording = true;
    logInterruptChain("start_capture_started", {
      recorderState: interruptRecorder?.state ?? null,
      timesliceMs: 100,
      path: "prearm_commit",
      asrMode,
    });
    _dbgState("recorder_started", { path: "prearm_commit" });
    logInterruptTranscriptDebug("capture_committed", {
      included_preroll_ms: Math.min(
        MAX_INTERRUPTION_PREROLL_MS,
        Math.max(0, interruptPrearmCommittedAt - interruptPrearmStartedAt)
      ),
      live_capture_started_at_ms: Number((interruptPrearmStartedAt || 0).toFixed(1)),
      bubble_created_at_ms: null,
      asr_request_started_at_ms: null
    });
    return;
  }

  // ---------- START FRESH RECORDER ----------
  if (!isMicStreamLiveForInterrupt()) {
    interruptRecording = false;
    interruptChunks = [];
    logInterruptTranscriptDebug("prearm", {
      stream_active: false,
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: INTERRUPTION_PREROLL_MS,
      reason: "no_active_mic_stream"
    });
    logInterruptChain("start_capture_skipped", {
      reason: "no_active_mic_stream",
      asrMode,
      trackStates: getInterruptMicTrackStates(),
    });
    _dbgState("start_aborted", { reason: "no_active_mic_stream" });
    return;
  }
  /* PART 12: use shared opus-preferred recorder helper so interrupt-path
     audio matches the quality of the main + hybrid recorders. */
  interruptRecorder = createVeraMediaRecorder(micStream);

  interruptRecorder.ondataavailable = (e) => {
    if (e.data && e.data.size > 0) {
      interruptChunks.push(e.data);
    }
  };

  interruptRecorder.onstop = () => {
    _dbgState("recorder_stopped", { path: "fresh_recorder" });
    const chunksCount = interruptChunks.length;
    const blob = new Blob(interruptChunks, { type: "audio/webm" });
    logInterruptChain("interrupt_audio_finalized", {
      blobSize: blob.size,
      chunksCount,
      durationMsApprox: interruptPrearmStartedAt
        ? Number(Math.max(0, performance.now() - interruptPrearmStartedAt).toFixed(1))
        : null,
      willSendToWhisper: blob.size >= MIN_AUDIO_BYTES && whisperInterruptCaptureNeeded(),
      path: "fresh_recorder",
    });

    interruptRecorder = null;
    interruptRecording = false;
    interruptChunks = [];

    handleInterruptUtterance(blob);
  };

  interruptRecorder.start(100);
  interruptRecording = true;
  logInterruptChain("start_capture_started", {
    recorderState: interruptRecorder?.state ?? null,
    timesliceMs: 100,
    path: "fresh_recorder",
    asrMode,
  });
  _dbgState("recorder_started", { path: "fresh_recorder" });
}

async function prearmInterruptCaptureForTts({ turnId = "", ttsId = "" } = {}) {
  /* DEBUG: capture-state log on entry so we can see whether prearm even
     ran for the news response. */
  logVeraInterruptDebug({
    tag: "interrupt_capture_state",
    event: "prearm_called",
    now: Number(performance.now().toFixed(1)),
    listeningMode,
    inputMuted,
    ttsId: ttsId || null,
    turnId: turnId || null,
    interruptRecording,
    prearmActive: Boolean(interruptPrearmRecorder && interruptPrearmRecorder.state === "recording"),
    ttsPlaying: (function () { try { return isAssistantTtsPlaying(); } catch (_) { return null; } })(),
    actionType: _veraCurrentTtsDebugContext?.actionType ?? null,
  });
  if (listeningMode !== "continuous" || inputMuted) {
    logVeraInterruptDebug({
      tag: "interrupt_capture_state",
      event: "prearm_aborted",
      reason: listeningMode !== "continuous" ? "not_continuous" : "input_muted",
      now: Number(performance.now().toFixed(1)),
    });
    return false;
  }
  if (!isAssistantTtsPlaying()) {
    logVeraInterruptDebug({
      tag: "interrupt_capture_state",
      event: "prearm_aborted",
      reason: "tts_not_playing",
      now: Number(performance.now().toFixed(1)),
      mainTtsPlaybackActive,
      activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
    });
    return false;
  }
  const micPermissionState = await getMicPermissionStateForInterrupt();
  const attempted =
    micPermissionState === "granted" ||
    isMicStreamLiveForInterrupt() ||
    (browserAsrPreferred() && !isNarrowViewport());
  logInterruptTranscriptDebug("tts_start", {
    turn_id: turnId || null,
    tts_id: ttsId || null,
    mic_permission_state: micPermissionState,
    prearm_attempted: attempted,
    prearm_success: false
  });
  if (!attempted || micPermissionState === "prompt" || micPermissionState === "denied") {
    return false;
  }

  interruptPrearmTtsId = ttsId || interruptPrearmTtsId || interruptTranscriptNewTtsId();
  interruptPrearmTurnId = turnId || interruptPrearmTurnId || "";

  if (browserAsrPreferred() && !isNarrowViewport()) {
    if (!interruptDetectRecognition) {
      startInterruptBrowserPartialDetection();
    }
    interruptPrearmSuccess = Boolean(interruptDetectRecognition);
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: 0,
      browser_asr_prearmed: interruptPrearmSuccess
    });
    logInterruptTranscriptDebug("tts_start", {
      turn_id: interruptPrearmTurnId || null,
      tts_id: interruptPrearmTtsId || null,
      mic_permission_state: micPermissionState,
      prearm_attempted: true,
      prearm_success: interruptPrearmSuccess
    });
    return interruptPrearmSuccess;
  }

  if (!micStream || !isMicStreamLiveForInterrupt() || typeof MediaRecorder === "undefined") {
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: INTERRUPTION_PREROLL_MS,
      reason: "no_media_recorder_or_stream"
    });
    return false;
  }

  try {
    if (interruptRecorder && interruptRecorder.state === "recording") {
      interruptPrearmSuccess = true;
      logInterruptTranscriptDebug("prearm", {
        stream_active: Boolean(micStream?.active),
        media_recorder_ready: true,
        rolling_buffer_enabled: true,
        preroll_ms: INTERRUPTION_PREROLL_MS,
        recorder_already_active: true
      });
      logInterruptTranscriptDebug("tts_start", {
        turn_id: interruptPrearmTurnId || null,
        tts_id: interruptPrearmTtsId || null,
        mic_permission_state: micPermissionState,
        prearm_attempted: true,
        prearm_success: true
      });
      return true;
    }
    if (interruptPrearmRecorder && interruptPrearmRecorder.state !== "inactive") return true;
    stopInterruptPrearmRecorder("");
    interruptPrearmChunks = [];
    interruptPrearmStartedAt = performance.now();
    /* PART 12: opus + bitrate so pre-arm captures sound as good as the
       main recorder. The "opening syllables get clipped" risk is mitigated
       by the prearm-start latency timing, not the encoder. */
    interruptPrearmRecorder = createVeraMediaRecorder(micStream);
    interruptPrearmRecorder.ondataavailable = (e) => {
      if (!e.data || e.data.size <= 0) return;
      interruptPrearmChunks.push({ blob: e.data, at: performance.now() });
      const cutoff = performance.now() - MAX_INTERRUPTION_PREROLL_MS;
      interruptPrearmChunks = interruptPrearmChunks.filter((x) => x.at >= cutoff);
    };
    interruptPrearmRecorder.onstop = () => {};
    interruptPrearmRecorder.start(100);
    interruptPrearmSuccess = true;
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: true,
      rolling_buffer_enabled: true,
      preroll_ms: INTERRUPTION_PREROLL_MS
    });
    logInterruptTranscriptDebug("tts_start", {
      turn_id: interruptPrearmTurnId || null,
      tts_id: interruptPrearmTtsId || null,
      mic_permission_state: micPermissionState,
      prearm_attempted: true,
      prearm_success: true
    });
    return true;
  } catch (err) {
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: INTERRUPTION_PREROLL_MS,
      error_message: String(err?.message || err || "").slice(0, 160)
    });
    return false;
  }
}

async function handleInterruptUtterance(blob) {
  const confirmationState = getWhisperInterruptConfirmationState();
  logWhisperInterruptQa("INTERRUPT_CANDIDATE_PIPELINE_ENTER", "handleInterruptUtterance", {
    blobSize: blob?.size ?? null,
    ...confirmationState,
  });
  /* DEBUG: log upload entry so we can see whether the interrupt capture
     made it all the way to the server upload step. If we never see this
     during a failed news interruption, the recorder either never started
     or never stopped. */
  logVeraInterruptDebug({
    tag: "interrupt_capture_state",
    event: "upload_started",
    now: Number(performance.now().toFixed(1)),
    blobSize: blob?.size ?? null,
    minAudioBytes: MIN_AUDIO_BYTES,
    skippedAsTooSmall: (blob?.size ?? 0) < MIN_AUDIO_BYTES,
    actionType: _veraCurrentTtsDebugContext?.actionType ?? null,
  });
  if (blob.size < MIN_AUDIO_BYTES) {
    logInterruptChain("interrupt_early_return", {
      reason: "blob_too_small",
      asrMode: (function () {
        try {
          return getVeraAsrMode();
        } catch (_) {
          return null;
        }
      })(),
      blobSize: blob.size,
    });
    listening = true;
    return;
  }

  requestInFlight = true;
  processing = true;
  /* PART 3 — log the "interrupted/listening" → "processing/thinking" hop
     that happens once the interrupt recorder closes the utterance. */
  _logVoiceStateTransition("listening", "processing", "interrupt_utterance_upload", "handleInterruptUtterance");
  waveState = "idle";
  setStatus("Thinking", "thinking");

  const formData = new FormData();
  formData.append("audio", blob);
  formData.append("session_id", getSessionId());
  formData.append("client", appModePrefix());
  formData.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));
  formData.append("mode", "interrupt"); // backend can branch if desired
  formData.append(
    "interrupt_debug",
    JSON.stringify({
      probe: lastInterruptProbe,
      thresholds: {
        INTERRUPT_RMS,
        INTERRUPT_ZCR_MIN,
        INTERRUPT_ZCR_MAX,
        INTERRUPT_SUSTAIN_MS: getInterruptSustainMs(),
        INTERRUPT_GAP_RESET_MS,
        INTERRUPT_MAX_CREST,
        MAX_SPEECH_RMS,
      },
    })
  );
  formData.append("stream_tts", shouldStreamTts() ? "1" : "0");

  logInterruptTranscriptDebug("capture_committed", {
    included_preroll_ms: interruptPrearmCommittedAt && interruptPrearmStartedAt
      ? Number(Math.min(MAX_INTERRUPTION_PREROLL_MS, interruptPrearmCommittedAt - interruptPrearmStartedAt).toFixed(1))
      : 0,
    live_capture_started_at_ms: Number((interruptPrearmStartedAt || performance.now()).toFixed(1)),
    bubble_created_at_ms: null,
    asr_request_started_at_ms: Number(performance.now().toFixed(1)),
    blob_size: blob.size
  });
  await runInferInterruptPipeline(formData);
}

function shouldConfirmWhisperInterruptTranscript() {
  return getWhisperInterruptConfirmationState().confirmationEnabled;
}

function handleWhisperInterruptTranscriptMissing(context = {}) {
  return rejectWhisperInterruptNoTranscript({
    ...context,
    via: "explicit_missing_handler",
  });
}

function describeInterruptTranscriptFlags(obj) {
  const o = obj && typeof obj === "object" ? obj : {};
  return {
    has_transcript: o.transcript != null && String(o.transcript).trim().length > 0,
    has_transcript_key: Object.prototype.hasOwnProperty.call(o, "transcript"),
    has_meta_transcript:
      o.meta?.transcript != null && String(o.meta.transcript).trim().length > 0,
    has_data_transcript:
      o.data?.transcript != null && String(o.data.transcript).trim().length > 0,
    has_text: o.text != null && String(o.text).trim().length > 0,
    has_asr_text: o.asr_text != null && String(o.asr_text).trim().length > 0,
    has_user_text: o.user_text != null && String(o.user_text).trim().length > 0,
    has_delta: o.delta != null && String(o.delta).trim().length > 0,
  };
}

function pickInterruptTranscriptFromObject(obj) {
  if (!obj || typeof obj !== "object") return "";
  for (const key of ["transcript", "asr_text", "user_text", "text"]) {
    if (obj[key] != null) return String(obj[key]).trim();
  }
  if (obj.meta?.transcript != null) return String(obj.meta.transcript).trim();
  if (obj.data?.transcript != null) return String(obj.data.transcript).trim();
  return "";
}

function shouldAttemptInterruptTranscriptConfirmationFromNdjsonLine(obj) {
  const eventType = String(obj?.type || obj?.event_type || "");
  if (eventType === "asr") return true;
  if (eventType === "meta") {
    return (
      Object.prototype.hasOwnProperty.call(obj, "transcript") ||
      Object.prototype.hasOwnProperty.call(obj, "user_text") ||
      Object.prototype.hasOwnProperty.call(obj, "asr_text") ||
      Object.prototype.hasOwnProperty.call(obj, "text") ||
      Boolean(pickInterruptTranscriptFromObject(obj))
    );
  }
  return Boolean(pickInterruptTranscriptFromObject(obj));
}

function rejectWhisperInterruptNoTranscript(context = {}) {
  logWhisperInterruptQa("WHISPER_INTERRUPT_NO_TRANSCRIPT_BEFORE_DONE", null, context);
  if (!shouldConfirmWhisperInterruptTranscript()) return true;
  logWhisperInterruptQa("INTERRUPT_REJECTED", "missing_transcript", context);
  ignoreWhisperInterruptCandidate("missing_transcript", {
    transcriptLen: 0,
    wordCount: 0,
  });
  return false;
}

function processWhisperInterruptNdjsonLine(obj, state, confirmationEnabled) {
  const eventType = String(obj?.type || obj?.event_type || "unknown");
  state.ndjsonEventCount += 1;
  if (eventType === "meta") state.sawMeta = true;
  if (eventType === "done") state.sawDone = true;
  if (eventType === "asr") state.sawAsr = true;

  logWhisperInterruptQa("WHISPER_INTERRUPT_NDJSON_LINE", null, {
    event_type: eventType,
    top_level_keys: Object.keys(obj || {}).slice(0, 24),
    ...describeInterruptTranscriptFlags(obj),
    responseMode: "ndjson",
  });

  if (!confirmationEnabled) return;
  if (state.whisperInterruptTranscriptRejected || state.whisperInterruptTranscriptConfirmed) {
    return;
  }
  if (!shouldAttemptInterruptTranscriptConfirmationFromNdjsonLine(obj)) return;

  state.sawTranscript = true;
  state.whisperInterruptTranscriptSeen = true;
  const transcriptText = pickInterruptTranscriptFromObject(obj);
  if (!handleWhisperInterruptTranscriptConfirmation(transcriptText)) {
    state.whisperInterruptTranscriptRejected = true;
    activePipelineAbort?.abort();
    return;
  }
  state.whisperInterruptTranscriptConfirmed = true;
}

function ignoreWhisperInterruptCandidate(rejectReason, { transcriptLen = 0, wordCount = 0 } = {}) {
  logInterruptChain("whisper_interrupt_ignored", {
    rejectReason,
    transcript_len: transcriptLen,
    word_count: wordCount,
  });
  _veraTtsCancelSource = "whisper_interrupt_ignored";
  activePipelineAbort?.abort();
  activePipelineAbort = null;
  cancelMainTtsPlayback();
  resetAudioHandlers();
  const a = getAudioEl();
  if (a) {
    a.pause();
    a.currentTime = 0;
  }
  hideSidePanel();
  cancelPendingNewsStatusBubble("whisper_interrupt_ignored");
  clearInterruptDetectionBubble();
  interruptBargeInLatched = false;
  processing = false;
  requestInFlight = false;
  voiceUxTurn = null;
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    listeningMode === "ptt" ? "idle" : "listening",
    "whisper_interrupt_ignored",
    "ignoreWhisperInterruptCandidate"
  );
  if (listeningMode === "ptt") {
    listening = false;
    pttRecording = false;
    waveState = "idle";
    setStatus("Ready", "idle");
    updateMuteInputButton();
  } else {
    waveState = "listening";
    listening = true;
    if (inputMuted) {
      showMutedStatusIfIdle();
    } else {
      setStatus("Listening…", "listening");
      window.setTimeout(() => {
        if (!listening || processing || inputMuted) return;
        startListening();
      }, 80);
    }
  }
  logWhisperInterruptQa("INTERRUPT_REJECTED_CLEANUP_DONE", null, {
    rejectReason,
    transcript_len: transcriptLen,
    word_count: wordCount,
  });
}

/**
 * Whisper stage-2 gate. Returns true when interrupt processing should continue.
 */
function handleWhisperInterruptTranscriptConfirmation(transcript) {
  const confirmation = evaluateWhisperInterruptTranscriptConfirmation(transcript);
  if (!shouldConfirmWhisperInterruptTranscript()) {
    logWhisperInterruptQa("WHISPER_INTERRUPT_TRANSCRIPT_RECEIVED", null, {
      transcript_len: confirmation.transcriptLen,
      word_count: confirmation.wordCount,
      accepted: true,
      rejectReason: null,
      confirmationSkipped: true,
      skipReason: "confirmation_not_enabled_for_asr_mode",
      ...getWhisperInterruptConfirmationState(),
    });
    return true;
  }
  logWhisperInterruptQa("WHISPER_INTERRUPT_TRANSCRIPT_RECEIVED", null, {
    transcript_len: confirmation.transcriptLen,
    word_count: confirmation.wordCount,
    accepted: confirmation.accepted,
    rejectReason: confirmation.rejectReason,
  });
  logInterruptChain("whisper_interrupt_transcript_received", {
    transcript_len: confirmation.transcriptLen,
    word_count: confirmation.wordCount,
    accepted: confirmation.accepted,
    rejectReason: confirmation.rejectReason,
  });
  if (!confirmation.accepted) {
    logWhisperInterruptQa("INTERRUPT_REJECTED", "whisper_transcript_rejected", {
      rejectReason: confirmation.rejectReason,
      transcript_len: confirmation.transcriptLen,
      word_count: confirmation.wordCount,
    });
    ignoreWhisperInterruptCandidate(confirmation.rejectReason, {
      transcriptLen: confirmation.transcriptLen,
      wordCount: confirmation.wordCount,
    });
    return false;
  }
  logWhisperInterruptQa("INTERRUPT_CONFIRMED", "whisper_transcript_accepted", {
    transcript_len: confirmation.transcriptLen,
    word_count: confirmation.wordCount,
  });
  logInterruptChain("whisper_interrupt_accepted", {
    transcript_len: confirmation.transcriptLen,
    word_count: confirmation.wordCount,
  });
  return true;
}

async function playInterruptAnswer(data) {
  const run = async () => {
    resetAudioHandlers();
    try {
      await playTtsFromApi(data, {
        onPlayStart: () => {
          logVoiceFirstAudio("main-reply");
          logVoiceMainReplyAudio();
          applyAssistantReplyAndPanels(data);
          /* PART 3 — interrupt-reply TTS starts: state hop into speaking. */
          _logVoiceStateTransition("processing", "speaking", "interrupt_reply_play_start", "playInterruptAnswer.onPlayStart");
          waveState = "speaking";
          audioStartedAt = performance.now();
          resetVadFastStopState("main_tts_start");
          setStatus("Speaking… (can only be interrupted once)", "speaking");
          processing = false;
        },
        onPlayEnd: () => {
          resumeListeningAfterInterruptPlayback();
        }
      });
    } catch (e) {
      console.warn(e);
    }
  };

  await run();
}
/* =========================
   MIC INIT
========================= */

/** Per-mode TTS <audio> through Web Audio (vera-audio / bmo-audio). */
async function ensureMainAudioTtsGraph() {
  const m = appModePrefix();
  const el = getAudioEl();
  if (!el || ttsByMode[m].source) return;
  if (!audioCtx) {
    audioCtx = new AudioContext({ sampleRate: 16000 });
  }
  await audioCtx.resume();
  const analyser = audioCtx.createAnalyser();
  analyser.fftSize = 2048;
  const gain = audioCtx.createGain();
  gain.gain.value = 1;
  const source = audioCtx.createMediaElementSource(el);
  source.connect(analyser);
  source.connect(gain);
  gain.connect(audioCtx.destination);
  ttsByMode[m].source = source;
  ttsByMode[m].analyser = analyser;
  ttsByMode[m].gain = gain;
  applyVeraWorkModeMuteSetting();
}

/** Prefer `audio_urls` when present (sentence-chunked TTS); else single `audio_url`. */
function resolveAudioUrls(data) {
  if (Array.isArray(data.audio_urls) && data.audio_urls.length) return data.audio_urls;
  if (data.audio_url) return [data.audio_url];
  return [];
}

/* =========================================================================
 *  MAIN-TTS RUNTIME STATE + BOOKKEEPING + CANCELLATION
 *  → moved to voice/ttsQueue.js (Stage 5, 2026-05-27).
 *
 *  Moved bindings:
 *    let activeMainTtsBufferSources, let mainTtsPlaybackActive,
 *    let mainTtsPlaybackToken, let activeNdjsonBodyReader,
 *    function registerMainTtsBufferSource,
 *    function stopAllMainTtsWebAudio,
 *    function cancelMainTtsPlayback.
 *
 *  isAssistantTtsPlaying remains here because many non-TTS sites call
 *  it; it still reads the moved state via the shared classic-script
 *  global lexical environment.
 * ========================================================================= */

/* MAIN-TTS PIPELINE BOOKKEEPING (isAssistantTtsPlaying,
 * activePipelineAbort, queuedAssistantTtsPlayback,
 * attachPipelineAbortSignal, enqueueAssistantTtsPlayback,
 * waitUntilAssistantTtsIdle) -> moved to voice/ttsQueue.js
 * (Stage 21 / Patch A-7, 2026-05-31). voice/ttsQueue.js loads before
 * app.js per index.html, so the moved function declarations and the
 * two top-level `let` bindings are visible to every later classic
 * script through the shared global lexical environment at call time.
 * Stage 5 (the file that created voice/ttsQueue.js) explicitly listed
 * these as future-move candidates in its header comment. */

async function waitForAssistantPlaybackEnd(onFinishHook) {
  let done = false;
  let resolveDone;
  const donePromise = new Promise((resolve) => {
    resolveDone = resolve;
  });
  const finishDone = () => {
    if (done) return;
    done = true;
    resolveDone?.();
  };
  const wrappedOnFinish = () => {
    try {
      if (typeof onFinishHook === "function") onFinishHook();
    } finally {
      finishDone();
    }
  };
  // Safety timeout in case a browser event is missed.
  const timeoutId = window.setTimeout(finishDone, 45000);
  return {
    wrappedOnFinish,
    donePromise: donePromise.finally(() => window.clearTimeout(timeoutId))
  };
}

function isMainTtsOrHtmlAudioPlaying() {
  const a = getAudioEl();
  const htmlPlaying = a && !a.paused;
  const webTts =
    activeMainTtsBufferSources.length > 0 || mainTtsPlaybackActive;
  return htmlPlaying || webTts;
}

function isServerPipelineBusy() {
  return (
    requestInFlight ||
    processing ||
    isMainTtsOrHtmlAudioPlaying()
  );
}

/** Typed send (flow or work mode) can replace an in-flight reply / speaking TTS. */
function isFlowModeKeyboardInterruptAllowed() {
  return true;
}

/** Abort fetch + stop main TTS so the next `/text` send can proceed (keyboard barge-in). */
function interruptAssistantPipelineForTypedMessage() {
  /* PART 3/4 — typed keyboard barge-in is structurally similar to voice
     barge-in: log the state transition so the trace shows where TTS got
     cancelled when the user typed instead of spoke. */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    "interrupted",
    "typed_pipeline_barge_in",
    "interruptAssistantPipelineForTypedMessage"
  );
  activePipelineAbort?.abort();
  activePipelineAbort = null;
  _veraTtsCancelSource = "typed_pipeline_barge_in";
  cancelMainTtsPlayback();
  resetAudioHandlers();
  const a = getAudioEl();
  if (a) {
    a.pause();
    a.currentTime = 0;
  }
  processing = false;
  requestInFlight = false;
  // The prior assistant request is gone — any pending "Searching news…"
  // bubble that was waiting on it would never resolve.
  cancelPendingNewsStatusBubble("pipeline_interrupted_by_typed");
  clearInterruptDetectionBubble();
  interruptBargeInLatched = false;
  voiceUxTurn = null;
  textUxTurn = null;
  if (listeningMode === "ptt") {
    listening = false;
    pttRecording = false;
    waveState = "idle";
    setStatus("Ready", "idle");
  } else {
    listening = true;
    waveState = "listening";
    if (inputMuted) showMutedStatusIfIdle();
    else setStatus("Listening…", "recording");
  }
  updateMuteInputButton();
}

function cancelVoicePipelineAndResetState() {
  /* PART 3 — full pipeline reset (e.g. mode swap, error recovery). */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    "idle",
    "voice_pipeline_reset",
    "cancelVoicePipelineAndResetState"
  );
  // Diagnostic: if a non-cancelable action was just committed (sync /
  // add / remove / update / toggle / timer), the audio cancellation
  // below is allowed but the underlying state mutation MUST NOT be
  // unwound. The helpers in this function never touch checklist /
  // timer state directly, so the policy is preserved — we log here so
  // any future regression is obvious in DevTools.
  if (wasNonCancelableActionRecentlyCommitted()) {
    logChecklistActionCommitDebug({
      phase: "interrupt_during_committed_action",
      action_type: lastCommittedNonCancelableAction?.action_type || null,
      committed_at: lastCommittedNonCancelableAction?.committed_at || 0,
      reset_state_touched: false,
      notes: "cancelling only audio — checklist/timer mutation preserved"
    });
  }
  activePipelineAbort?.abort();
  activePipelineAbort = null;
  _veraTtsCancelSource = "voice_pipeline_reset";
  cancelMainTtsPlayback();
  resetAudioHandlers();
  const a = getAudioEl();
  if (a) {
    a.pause();
    a.removeAttribute("src");
    a.load?.();
  }
  if (rafId) {
    cancelAnimationFrame(rafId);
    rafId = null;
  }
  if (speechWaitTimeoutId != null) {
    clearTimeout(speechWaitTimeoutId);
    speechWaitTimeoutId = null;
  }
  if (interruptRecorder && interruptRecorder.state !== "inactive") {
    try {
      interruptRecorder.ondataavailable = null;
      interruptRecorder.onstop = null;
      interruptRecorder.stop();
    } catch {}
  }
  interruptRecorder = null;
  interruptRecording = false;
  interruptChunks = [];
  stopInterruptPrearmRecorder("");
  stopAllBrowserSpeechRecognizers();
  if (mediaRecorder && mediaRecorder.state === "recording") {
    suppressNextUtterance = true;
    mediaRecorder.stop();
  }
  processing = false;
  requestInFlight = false;
  voiceUxTurn = null;
  textUxTurn = null;
  pttRecording = false;
  listening = false;
  audioChunks = [];
  hasSpoken = false;
  lastVoiceTime = 0;
  waveState = "idle";
  cancelPendingNewsStatusBubble("voice_pipeline_reset");
  clearVoiceMaxDurationTimer();
  setStatus("Ready", "idle");
  updateMuteInputButton();
}

function resumeAfterAssistantReplyPlayback() {
  /* PART 3 — natural end of an assistant reply: speaking → listening/idle. */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    listeningMode === "ptt" ? "idle" : "listening",
    "assistant_reply_playback_end",
    "resumeAfterAssistantReplyPlayback"
  );
  browserAsrMainNetworkRetries = 0;
  processing = false;
  requestInFlight = false;
  stopInterruptPrearmRecorder("");
  if (workModeTypedTurnQueue.length > 0) scheduleWorkModeTypedQueueDrain();
  clearInterruptDetectionBubble();
  if (listeningMode === "ptt") {
    listening = false;
    pttRecording = false;
    waveState = "idle";
    setStatus("Ready", "idle");
    updateMuteInputButton();
    return;
  }
  waveState = "listening";
  if (listeningMode === "continuous") {
    listening = true;
    if (inputMuted) {
      showMutedStatusIfIdle();
      return;
    }
    /* Defer so Web Audio / <audio> teardown and NDJSON reader finish; avoids empty SR sessions that never transcribe. */
    window.setTimeout(() => {
      if (!listening || processing || inputMuted) return;
      startListening();
    }, 80);
  }
}

function resumeListeningAfterInterruptPlayback() {
  /* PART 3 — natural end of an INTERRUPT reply playback. */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    listeningMode === "ptt" ? "idle" : "listening",
    "interrupt_reply_playback_end",
    "resumeListeningAfterInterruptPlayback"
  );
  browserAsrMainNetworkRetries = 0;
  processing = false;
  requestInFlight = false;
  stopInterruptPrearmRecorder("");
  clearInterruptDetectionBubble();
  if (listeningMode === "ptt") {
    listening = false;
    pttRecording = false;
    waveState = "idle";
    setStatus("Ready", "idle");
    updateMuteInputButton();
    return;
  }
  waveState = "listening";
  listening = true;
  if (inputMuted) {
    showMutedStatusIfIdle();
    return;
  }
  window.setTimeout(() => {
    if (!listening || processing || inputMuted) return;
    startListening();
  }, 80);
}

/** Same wiring as MediaElementSource → analyser + destination: chunked TTS must feed the TTS analyser or BMO mouth / VERA wave stay flat. */
function connectBufferSourceToTtsGraph(src) {
  const m = appModePrefix();
  const t = ttsByMode[m];
  if (t?.analyser) {
    src.connect(t.analyser);
  }
  if (t?.gain) src.connect(t.gain);
  else src.connect(audioCtx.destination);
}

function wrapLastChunkForBmoMouth(onLastEnd) {
  if (!onLastEnd) return undefined;
  return () => {
    mainTtsPlaybackActive = false;
    if (document.body.classList.contains("bmo-open")) {
      stopBmoTtsMouthAnimation();
    }
    onLastEnd();
  };
}

/** Mirrors `split_sentences_for_tts` / TTS.py: paragraphs, then `.!?` or newlines. */
function splitSentencesForTtsClient(text) {
  let t = (text || "").trim();
  if (!t) return [];
  t = t.replace(/\u201c/g, '"').replace(/\u201d/g, '"').replace(/\u2019/g, "'");
  t = t.replace(/\u3002/g, ".");
  t = t.replace(/(?<=[a-z])\.(?=[A-Z])/g, ". ");
  const paragraphs = t.split(/\n\s*\n+/);
  const out = [];
  for (const para of paragraphs) {
    const p = para.trim();
    if (!p) continue;
    const parts = p.split(/(?<=[.!?])\s+|\n+/);
    for (const part of parts) {
      const x = part.trim();
      if (x) out.push(x);
    }
  }
  return out.length ? out : [t];
}

const BMO_TTS_SAD_HINTS =
  /\b(sorry|sad|sorrow|cry|tears|tearful|afraid|scared|fear|worried|worry|anxious|anxiety|depress|lonely|alone|hurt|hurts|pain|aching|hate|hatred|angry|rage|terrible|awful|horrible|worst|tragic|unfortunately|regret|guilt|ashamed|loss|lose|lost|die|death|dead|dying|kill|never\s+again|hopeless|despair|upset|disappoint|failed?|failure|breakdown|grief|mourn)\b/i;
const BMO_TTS_HAPPY_HINTS =
  /\b(happy|happiness|joy|joyful|great|wonderful|awesome|amazing|love|loved|celebrat|excit|excited|fun|funny|laugh|smile|cheer|yay|best|lucky|glad|proud|relief|relieved|good\s+news|victory|won|win|beautiful|perfect)\b/i;
// Playful/idiomatic phrases that contain "negative" tokens but are clearly NOT sad.
// We test these BEFORE the sad hints so "never hurt anyone" stays neutral instead of
// flipping to a sad face on the bare 'hurt'/'pain'/'sorry' tokens.
const BMO_PLAYFUL_NEGATIVE_RX =
  /\b(never\s+(?:hurt|hurts|harmed|killed|cried|failed|did\s+anything)\s+(?:anyone|anybody|anything|nobody|no\s+one|a\s+soul)|(?:doesn|don|didn|won|wouldn|couldn|shouldn|can|cannot|cant)'?t\s+hurt(?:\s+(?:to|anyone|anybody|me|us|you|it))?|no\s+harm(?:\s+done|\s+in\s+(?:that|trying|asking))?|just\s+(?:kidding|teasing|joking|playing|messing\s+with\s+you)|only\s+(?:kidding|teasing|joking)|no\s+big\s+deal|nothing\s+to\s+worry\s+about|all\s+in\s+good\s+fun|grammatical\s+weathering)\b/i;

function bmoSentenceIsPlayfulNegative(seg) {
  const s = String(seg || "").trim();
  if (!s) return false;
  return BMO_PLAYFUL_NEGATIVE_RX.test(s);
}

function normalizeBmoTtsMood(x) {
  const s = String(x || "neutral").trim().toLowerCase();
  if (s === "sad" || s === "neutral" || s === "happy") return s;
  return "neutral";
}

function classifyBmoTtsSegmentHeuristic(seg) {
  const s = (seg || "").trim();
  if (!s) return "neutral";
  // Playful idiom guard: don't let bare 'hurt'/'pain'/'sorry' force sad on a clearly
  // playful sentence ("a little weathering never hurt anyone", "no harm done", etc.).
  if (bmoSentenceIsPlayfulNegative(s)) {
    if (BMO_TTS_HAPPY_HINTS.test(s) && !BMO_TTS_SAD_HINTS.test(s)) return "happy";
    return "neutral";
  }
  if (BMO_TTS_SAD_HINTS.test(s) && !BMO_TTS_HAPPY_HINTS.test(s)) return "sad";
  if (BMO_TTS_HAPPY_HINTS.test(s) && !BMO_TTS_SAD_HINTS.test(s)) return "happy";
  if (BMO_TTS_SAD_HINTS.test(s)) return "sad";
  if (BMO_TTS_HAPPY_HINTS.test(s)) return "happy";
  return "neutral";
}

/** Strict lexicon override — always force sad regardless of user_text or LLM label.
 *  Reserved for unambiguous grief / deep apology / condolences phrasings. Generic
 *  "sorry" / "wish I could" do NOT belong here; those move to the soft set below.
 */
function bmoAssistantSegmentRequiresSadFaceStrict(seg) {
  const s = String(seg || "").trim();
  if (!s) return false;
  if (bmoSentenceIsPlayfulNegative(s)) return false;
  if (
    /\b(my\s+condolences|deepest\s+condolences|so\s+sorry\s+for\s+your\s+loss|i'?m\s+so\s+sorry\s+to\s+hear|that'?s\s+(?:so\s+)?heartbreaking|that\s+sounds\s+(?:truly|really)\s+(?:awful|devastating|heartbreaking))\b/i.test(
      s
    )
  ) {
    return true;
  }
  return false;
}

/** Soft empathy/apology — only forces sad when the USER_text shows distress. */
function bmoAssistantSegmentSoftEmpathy(seg) {
  const s = String(seg || "").trim();
  if (!s) return false;
  if (bmoSentenceIsPlayfulNegative(s)) return false;
  if (/\b(sorry|apologi[sz]e|apologies)\b/i.test(s)) return true;
  if (/\b(i\s*'?m\s+sorry|i\s+am\s+sorry|we\s*'?re\s+sorry|so\s+sorry|really\s+sorry|deeply\s+sorry)\b/i.test(s))
    return true;
  if (/\b(sorry\s+you'?re|sorry\s+to\s+hear|sorry\s+about|sorry\s+for)\b/i.test(s)) return true;
  if (
    /\b(that\s+sounds\s+(?:really\s+)?(?:hard|rough|awful|tough|difficult)|hearing\s+(?:that|you)|wish\s+i\s+could|i\s+hear\s+you|i'?m\s+here\s+for\s+you)\b/i.test(
      s
    )
  )
    return true;
  return false;
}

// Tightened user-distress hint: bare tokens like "down" / "blue" / "alone" / "hurt"
// / "pain" require accompanying "feel(ing)" or "I'm" context so casual phrasing
// like "Trump is going down to China" doesn't promote BMO to sad mode.
const BMO_USER_DISTRESS_RX =
  /\b(sad|depressed|depressing|anxious|anxiety|worried|worries|cry|crying|tearful|grief|grieving|mourning|hopeless|despair|despairing|overwhelmed|exhausted|drained|can'?t\s+cope|cannot\s+cope|cant\s+cope|not\s+ok(?:ay)?|having\s+a\s+(?:hard|tough|rough)\s+time|need\s+(?:to\s+)?(?:cry|vent|talk))\b|\bfeel(?:ing)?\s+(?:down|blue|empty|numb|lonely|alone|sad|hurt|broken|hopeless|low|terrible|awful|miserable|like\s+crap|like\s+shit)\b|\bi'?m\s+(?:hurting|hurt|in\s+pain|crying|broken|lost|done|struggling|overwhelmed|exhausted|drained|not\s+ok(?:ay)?|miserable|grieving)\b/i;

function bmoUserTextIsDistressed(userText) {
  const ut = String(userText || "").trim();
  if (!ut) return false;
  return BMO_USER_DISTRESS_RX.test(ut);
}

/** Backward-compat name still used by callers in this file. */
function bmoAssistantSegmentPrefersSadFace(seg, userText) {
  if (bmoAssistantSegmentRequiresSadFaceStrict(seg)) return true;
  if (bmoUserTextIsDistressed(userText) && bmoAssistantSegmentSoftEmpathy(seg)) return true;
  return false;
}

/**
 * If TTS is one file for many sentences, any STRICT apology (condolences, deep grief)
 * in the reply deserves the sad mouth even when modes is a single-element array.
 * SOFT empathy ("I'm sorry", "wish I could") only flips when userText is distressed.
 */
function applyBmoSadFaceLexiconOverride(sentences, faceModes, userText) {
  if (!Array.isArray(sentences) || !Array.isArray(faceModes) || !faceModes.length) return faceModes;
  const distressed = bmoUserTextIsDistressed(userText);
  const shouldOverride = (s) => {
    if (bmoAssistantSegmentRequiresSadFaceStrict(s)) return true;
    if (distressed && bmoAssistantSegmentSoftEmpathy(s)) return true;
    return false;
  };
  if (faceModes.length === 1 && sentences.length > 1) {
    if (sentences.some(shouldOverride)) return ["sad"];
    return faceModes;
  }
  return faceModes.map((mode, i) => (shouldOverride(sentences[i]) ? "sad" : mode));
}

function logBmoEmotionDecision(row) {
  try {
    console.log("[bmo_emotion_decision]", JSON.stringify(row));
  } catch {}
}

function bmoMoodToFaceMode(mood) {
  return normalizeBmoTtsMood(mood) === "sad" ? "sad" : "happy";
}

/** When the user sounded clearly distressed, do not keep empathy/apology sentences as
 *  neutral (LLM often does). Casual user phrasing must NOT trigger this — playful
 *  idioms in the assistant reply are left alone via the playful-negative guard.
 */
function boostBmoMoodsForUserDistress(userText, sentences, moods) {
  const ut = (userText || "").trim();
  if (!ut || !Array.isArray(sentences) || !Array.isArray(moods) || moods.length !== sentences.length) {
    return moods;
  }
  if (!bmoUserTextIsDistressed(ut)) return moods;
  return moods.map((m, i) => {
    const lab = normalizeBmoTtsMood(m);
    if (lab === "sad" || lab === "happy") return lab;
    const s = String(sentences[i] || "");
    if (bmoSentenceIsPlayfulNegative(s)) return lab;
    if (bmoAssistantSegmentSoftEmpathy(s) || bmoAssistantSegmentRequiresSadFaceStrict(s)) {
      return "sad";
    }
    return lab;
  });
}

function alignBmoFaceModesToChunkCount(modes, chunkCount) {
  const n = Math.max(0, chunkCount | 0);
  if (!n) return [];
  const m = Array.isArray(modes) ? modes.slice(0, n) : [];
  const last = m.length ? m[m.length - 1] : "happy";
  while (m.length < n) m.push(last);
  for (let i = 0; i < m.length; i++) {
    m[i] = m[i] === "sad" ? "sad" : "happy";
  }
  return m;
}

function bmoNewSegmentFromCumulativeReply(prevCum, newCum) {
  const p = (prevCum || "").trimEnd();
  const c = (newCum || "").trim();
  if (!c) return "";
  if (!p) return c;
  if (c === p) return "";
  if (c.startsWith(p)) return c.slice(p.length).trimStart();
  return c;
}

function setBmoTtsFaceTrack(track) {
  const svg = document.getElementById("bmo-smile-svg");
  if (!svg) return;
  if (track === "sad") svg.setAttribute("data-bmo-tts-face-track", "sad");
  else svg.removeAttribute("data-bmo-tts-face-track");
}

async function fetchBmoTtsEmotionLabels(userText, sentences) {
  const res = await fetch(`${API_URL}/tts_emotion_route`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      session_id: getSessionId(),
      user_text: userText || "",
      sentences
    })
  });
  if (!res.ok) throw new Error(`emotion route HTTP ${res.status}`);
  const data = await res.json();
  const raw = data.labels;
  if (!Array.isArray(raw)) throw new Error("emotion route: missing labels");
  return sentences.map((_, i) => normalizeBmoTtsMood(raw[i]));
}

async function resolveBmoTtsSegmentFaceModesForPlayback(data, urlCount) {
  if (!document.body.classList.contains("bmo-open")) return null;
  const n = Math.max(0, urlCount | 0);
  if (!n) return null;
  const reply = String(data?.reply ?? "").trim();
  const userText = String(
    data?.transcript ?? data?.user_text ?? data?.text ?? ""
  ).trim();
  if (!reply) return alignBmoFaceModesToChunkCount([], n);
  const sentences = splitSentencesForTtsClient(reply);
  if (!sentences.length) return alignBmoFaceModesToChunkCount([], n);

  // Heuristic per sentence — always computed so we can include it in [bmo_emotion_decision].
  const heuristicLabels = sentences.map((s) => classifyBmoTtsSegmentHeuristic(s));

  // LLM labels are PRIMARY when available; heuristic is only a fallback.
  let llmLabels = null;
  try {
    llmLabels = await fetchBmoTtsEmotionLabels(userText, sentences);
  } catch (e) {
    console.warn("[BMO][TTS] emotion route", e);
    llmLabels = null;
  }
  const primary = llmLabels || heuristicLabels.slice();
  const boosted = boostBmoMoodsForUserDistress(userText, sentences, primary);

  let modes = sentences.map((_, i) => bmoMoodToFaceMode(boosted[i]));
  modes = alignBmoFaceModesToChunkCount(modes, n);
  // Lexicon override now requires either a STRICT phrase (always) or SOFT empathy
  // + a clearly distressed user (never on a single bare 'sorry' / 'hurt' alone).
  modes = applyBmoSadFaceLexiconOverride(sentences, modes, userText);

  for (let i = 0; i < sentences.length; i++) {
    const llm = llmLabels ? normalizeBmoTtsMood(llmLabels[i]) : null;
    const heur = normalizeBmoTtsMood(heuristicLabels[i]);
    const final = normalizeBmoTtsMood(boosted[i]);
    let overrideApplied = false;
    let overrideReason = "";
    if (llm && llm !== final) {
      overrideApplied = true;
      if (llm === "sad" && final !== "sad" && bmoSentenceIsPlayfulNegative(sentences[i])) {
        overrideReason = "demoted_playful_negative";
      } else if (final === "sad") {
        if (bmoAssistantSegmentRequiresSadFaceStrict(sentences[i])) {
          overrideReason = "strict_empathy_lexicon";
        } else if (bmoUserTextIsDistressed(userText) && bmoAssistantSegmentSoftEmpathy(sentences[i])) {
          overrideReason = "soft_empathy_with_user_distress";
        } else {
          overrideReason = "boost_for_user_distress";
        }
      } else {
        overrideReason = "label_changed";
      }
    } else if (!llm) {
      overrideReason = "heuristic_fallback";
    }
    logBmoEmotionDecision({
      sentence: String(sentences[i] || "").slice(0, 200),
      user_text: String(userText || "").slice(0, 200),
      llm_label: llm,
      heuristic_label: heur,
      final_label: final,
      override_applied: overrideApplied,
      override_reason: overrideReason,
    });
  }

  return modes;
}

/* playTtsUrlSequenceGapless → moved to voice/ttsQueue.js (Stage 5, 2026-05-27). */

/** Single <audio> for one file; Web Audio queue when multiple sentence chunks. */
async function playTtsFromApi(data, { onPlayStart, onPlayEnd, ephemeralAck } = {}) {
  const cleanupAfterFailedTtsPlay = (reason, extra = {}) => {
    try {
      console.warn("[tts_play_failed_cleanup_done]", {
        reason,
        tts_segment_count: data?.tts_segment_count ?? null,
        audio_url_present: Boolean(data?.audio_url),
        audio_urls_count: Array.isArray(data?.audio_urls) ? data.audio_urls.length : 0,
        audio_file_exists: null,
        ...extra
      });
    } catch (_) {}
    mainTtsPlaybackActive = false;
    try { activeMainTtsBufferSources.length = 0; } catch (_) {}
    try {
      const a = getAudioEl();
      if (a) {
        a.pause();
        a.removeAttribute("src");
        a.load?.();
      }
    } catch (_) {}
    if (typeof onPlayEnd === "function") onPlayEnd();
  };
  if (appModePrefix() === "vera" && isVeraWorkModeOn() && isWorkModeMuteEnabled()) {
    logVeraSettings("tts_play_suppressed_workmode_mute", { mode: "playTtsFromApi" });
    mainTtsPlaybackActive = false;
    if (typeof onPlayStart === "function") onPlayStart();
    if (typeof onPlayEnd === "function") onPlayEnd();
    return;
  }
  if (!ephemeralAck && listeningMode === "continuous" && inputMuted) {
    logVeraSettings("tts_play_suppressed_continuous_input_muted", { mode: "playTtsFromApi" });
    mainTtsPlaybackActive = false;
    if (typeof onPlayStart === "function") onPlayStart();
    waveState = "idle";
    processing = false;
    requestInFlight = false;
    showMutedStatusIfIdle();
    if (typeof onPlayEnd === "function") onPlayEnd();
    return;
  }
  const urls = resolveAudioUrls(data);
  try {
    console.info("[tts_state_before_play]", {
      tts_segment_count: data?.tts_segment_count ?? null,
      audio_url_present: Boolean(data?.audio_url),
      audio_urls_count: urls.length,
      mainTtsPlaybackActive,
      activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
      waveState,
      requestInFlight,
      processing,
      workModeTtsQueueLength: Array.isArray(workModeTtsQueue) ? workModeTtsQueue.length : null,
      workModeTtsDrainActive: Boolean(workModeTtsDrainRunning),
      currentWorkModeTtsItem: workModeTtsCurrentlyPlaying || null
    });
  } catch (_) {}
  if (!urls.length) {
    try {
      if (typeof onPlayStart === "function") onPlayStart();
    } catch (_) {}
    cleanupAfterFailedTtsPlay("no_audio_urls", {
      audio_play_error: "no_audio_urls",
      audio_error_code: null
    });
    return;
  }

  let segmentFaceModes = null;
  if (document.body.classList.contains("bmo-open")) {
    segmentFaceModes = await resolveBmoTtsSegmentFaceModesForPlayback(data, urls.length);
  }

  if (urls.length > 1) {
    console.log(
      `[UX][TTS] ${urls.length} segments — one /text or /infer response; next: ${urls.length} GETs to /audio/...`,
      urls
    );
  }

  const sessionToken = mainTtsPlaybackToken;
  const runPlayStart = () => {
    if (onPlayStart) onPlayStart();
  };

  if (urls.length === 1) {
    const el = getAudioEl();
    if (!el) {
      cleanupAfterFailedTtsPlay("missing_audio_element", {
        audio_play_error: "missing_audio_element",
        audio_error_code: null
      });
      return;
    }
    el.src = `${API_URL}${urls[0]}`;
    await ensureMainAudioTtsGraph();
    el.addEventListener(
      "play",
      () => {
        mainTtsPlaybackActive = true;
        if (document.body.classList.contains("bmo-open")) {
          const face =
            segmentFaceModes != null && segmentFaceModes.length
              ? segmentFaceModes[0]
              : "happy";
          setBmoTtsFaceTrack(face);
          void startBmoTtsMouthAnimation();
        }
        runPlayStart();
      },
      { once: true }
    );
    el.addEventListener(
      "ended",
      () => {
        mainTtsPlaybackActive = false;
        try {
          console.info("[tts_state_after_done]", {
            mainTtsPlaybackActive,
            activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
            waveState,
            requestInFlight,
            processing
          });
        } catch (_) {}
        if (onPlayEnd) onPlayEnd();
        try {
          console.info("[tts_state_after_finally]", {
            mainTtsPlaybackActive,
            activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
            waveState,
            requestInFlight,
            processing,
            workModeTtsQueueLength: Array.isArray(workModeTtsQueue) ? workModeTtsQueue.length : null,
            workModeTtsDrainActive: Boolean(workModeTtsDrainRunning),
            currentWorkModeTtsItem: workModeTtsCurrentlyPlaying || null
          });
        } catch (_) {}
      },
      { once: true }
    );
    const onSingleAudioError = (ev) => {
      try { el.removeEventListener("error", onSingleAudioError); } catch (_) {}
      try {
        console.warn("[audio_play_error]", {
          audio_fetch_status: null,
          audio_play_error: String(ev?.message || ev || "audio_element_error"),
          audio_error_code: el.error?.code ?? null,
          src: el.src
        });
      } catch (_) {}
      logVeraCapabilityFailure("tts", "audio_element_error", {
        src: el.src,
        error_code: el.error?.code
      });
      logCapabilityFallbackDebug({
        capability: "speaking",
        failure_kind: "inference_error",
        should_show_bubble: true,
        source_function: "playTtsFromApi.onSingleAudioError",
        raw_error_message: `audio_error_code=${el.error?.code ?? "?"}`
      });
      mainTtsPlaybackActive = false;
      veraShowCapabilityFailureBubble(
        "tts_failure",
        VERA_SAFETY_LIMITS.messages.ttsFailure
      );
      cleanupAfterFailedTtsPlay("audio_element_error", {
        audio_play_error: String(ev?.message || ev || "audio_element_error"),
        audio_error_code: el.error?.code ?? null,
        src: el.src
      });
    };
    el.addEventListener("error", onSingleAudioError, { once: true });
    try {
      console.info("[audio_play_attempt]", { url: urls[0], mode: "html_audio" });
      await el.play();
      console.info("[audio_play_success]", { url: urls[0], mode: "html_audio" });
    } catch (err) {
      onSingleAudioError(err);
    }
    return;
  }

  try {
    console.info("[audio_play_attempt]", { urls, mode: "web_audio_gapless" });
    await playTtsUrlSequenceGapless(API_URL, urls, {
      onFirstStart: () => {
        console.info("[audio_play_success]", { first_url: urls[0], mode: "web_audio_gapless" });
        runPlayStart();
      },
      onLastEnd: () => {
        try {
          console.info("[tts_state_after_done]", {
            mainTtsPlaybackActive,
            activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
            waveState,
            requestInFlight,
            processing
          });
        } catch (_) {}
        if (onPlayEnd) onPlayEnd();
      },
      sessionToken,
      segmentFaceModes
    });
  } catch (e) {
    try {
      console.warn("[tts_state_after_play_error]", {
        error: String(e?.message || e || ""),
        mainTtsPlaybackActive,
        activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
        waveState,
        requestInFlight,
        processing
      });
    } catch (_) {}
    cleanupAfterFailedTtsPlay("web_audio_gapless_error", {
      audio_play_error: String(e?.message || e || ""),
      audio_error_code: null
    });
  } finally {
    try {
      console.info("[tts_state_after_finally]", {
        mainTtsPlaybackActive,
        activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
        waveState,
        requestInFlight,
        processing,
        workModeTtsQueueLength: Array.isArray(workModeTtsQueue) ? workModeTtsQueue.length : null,
        workModeTtsDrainActive: Boolean(workModeTtsDrainRunning),
        currentWorkModeTtsItem: workModeTtsCurrentlyPlaying || null
      });
    } catch (_) {}
  }
}

